# XPX_Preload.rb
# Auto-generated by XPX Engine — do not edit manually.

# Developer-mode flag. When true, XPX runtime patches print their
# `[XPX] ...` traces to the game console alongside writing them to
# xpx_debug.log. When false (the default for end-user builds), the
# console stays clean — file logging still happens so bug reports
# remain useful. Set by the editor at preload-write time based on
# whether the running editor is Mizzy's dev source build vs. a
# compiled / public release build.
XPX_DEV_MODE = false

# Top-level helper for the many `xpx_puts "..."` debug breadcrumbs
# scattered through this preload (autotile patches, tilemap wraps,
# etc.). Routing them through xpx_puts means a single XPX_DEV_MODE
# check controls whether they reach the game console — flip the
# constant above and every breadcrumb obeys instantly. Defined at
# top-level so it's available BEFORE the XPX module is opened (the
# Experimental Smoothness block emits puts calls before the module
# exists). Ruby promotes top-level defs to private Object methods,
# so it works in any context that `puts` does.
def xpx_puts(msg)
  puts "[XPX] #{msg}" if XPX_DEV_MODE
end

# JSON is required — XPX prefers .xpxdata over .rxdata when both exist,
# and the xpxdata loader (XPX.get_map below) parses JSON directly. The
# rescue is a safety net for unusual Ruby builds without the json stdlib;
# in that case the xpxdata path silently falls back to rxdata.
begin
  require 'json'
rescue LoadError
  # json gem unavailable; xpxdata fallback disabled (rxdata files are used)
end
# (No Scripts/ plugin uses Rails-style starts_with? / ends_with? — polyfill omitted.)

# (Experimental Smoothness OFF: game_es=False, game_fps=40 — no frame_count override emitted.)

module XPX
  GAME_ROOT = File.dirname(File.expand_path($0))
  MAPS_DIR  = File.join(GAME_ROOT, "Data", "maps")
  # All diagnostic logs live under <GAME_ROOT>/logs/ — single tidy folder
  # instead of scattering xpx_debug.log / xpx_audio_debug.log / etc. at
  # the project root. Older builds wrote xpx_debug.log to GAME_ROOT, so
  # we migrate any legacy file into the new folder on first write below.
  LOGS_DIR  = File.join(GAME_ROOT, "logs")
  LOG_PATH  = File.join(LOGS_DIR, "xpx_debug.log")
  begin
    Dir.mkdir(LOGS_DIR) unless File.directory?(LOGS_DIR)
  rescue; end
  # One-shot legacy migration: if an older xpx_debug.log lives at the
  # project root, move it into the logs folder so the user keeps their
  # history. Best-effort — silent on failure (the next write just goes
  # to the new path and the legacy file lingers harmlessly).
  begin
    legacy = File.join(GAME_ROOT, "xpx_debug.log")
    if File.exist?(legacy) && !File.exist?(LOG_PATH)
      File.rename(legacy, LOG_PATH) rescue nil
    end
  rescue; end

  # Suppress libpng sRGB warnings — these fire every frame per PNG and tank FPS
  begin
    $stderr.reopen(File.open(File::NULL, "w")) rescue nil
  rescue; end

  def self.log(msg)
    # File logging is ALWAYS on — bug reports need the trace.
    begin
      File.open(LOG_PATH, "a") {|f| f.puts "[#{Time.now.strftime('%H:%M:%S')}] #{msg}"; f.flush}
    rescue; end
    # Console output goes through xpx_puts, which has its own
    # XPX_DEV_MODE gate — end users see a clean game-console window;
    # devs (Mizzy) get every trace live.
    xpx_puts msg
  end

  # Console-only diagnostic for cases where we explicitly want output
  # ONLY to the game console (no file). Used for environment dumps /
  # GL info / etc. that would bloat the file log for every player but
  # help dev-side eyeballing. xpx_puts' own gate handles the dev/end-
  # user split.
  def self.console_log(msg)
    xpx_puts msg
  end

  def self.boot
    begin
      File.open(LOG_PATH, "w") do |f|
        f.puts "=== XPX Debug Log #{Time.now} ==="
        f.puts "Ruby: #{RUBY_VERSION} Platform: #{RUBY_PLATFORM}"
        f.puts "GAME_ROOT : #{GAME_ROOT}"
        f.puts "MAPS_DIR  : #{MAPS_DIR}"
        f.puts "LOG_PATH  : #{LOG_PATH}"
        f.puts "$0        : #{$0}"
        f.flush
      end
    rescue => log_err
      xpx_puts "WARNING: cannot write log: #{log_err.message}"
    end
    xpx_puts "Log: #{LOG_PATH}"
    log "Boot started. MAPS_DIR=#{MAPS_DIR}"
    log "Ruby: #{RUBY_VERSION}, JSON available: #{defined?(JSON) ? 'YES' : 'NO'}"
    log "Platform: #{RUBY_PLATFORM}, encoding default_external=#{Encoding.default_external}, default_internal=#{Encoding.default_internal}"

    # ── Runtime file inventory ───────────────────────────────────────────────
    # Logs every .exe/.dll in GAME_ROOT with size + mtime. This proves
    # what's actually loaded at runtime — critical for diagnosing wrong
    # DLL version issues (e.g. user kept their Pokémon Essentials Ruby
    # DLL alongside an XPX Game.exe that expects a different ABI).
    #
    # Also flags any Game.rgssad / Game.rgss2a / Game.rgss3a archive,
    # since mkxp-z prefers reading scripts and data from these encrypted
    # archives over loose files when both exist — meaning XPX's edits
    # to System.rxdata might be silently overridden by an .rgssad sibling.
    log "=== Runtime file inventory ==="
    begin
      Dir.entries(GAME_ROOT).sort.each do |f|
        next if f == "." || f == ".."
        full = File.join(GAME_ROOT, f)
        next unless File.file?(full)
        ext = File.extname(f).downcase
        if [".exe", ".dll"].include?(ext)
          st = File.stat(full)
          log "  #{f}: #{st.size} bytes, mtime=#{st.mtime.strftime('%Y-%m-%d %H:%M:%S')}"
        end
        if f =~ /\.rgss[1-9a-z]*\z/i
          st = File.stat(full)
          log "  ⚠ #{f} present (#{st.size} bytes) — mkxp-z may read scripts/data from this encrypted archive instead of loose files. Delete it if XPX edits aren't taking effect."
        end
      end
    rescue => e
      log "  (inventory failed: #{e.class}: #{e.message})"
    end

    # ── Ground-truth System.rxdata audit ─────────────────────────────────────
    # Load System.rxdata directly with Marshal BEFORE Essentials touches
    # anything, and log the start_map_id / start_x / start_y exactly as
    # they appear on disk. If the runtime later raises "No starting
    # position was set in the map editor", this log line proves whether
    # the file content is wrong (XPX didn't write it correctly) or the
    # Essentials scripts are reading something else.
    #
    # Also logs the file's mtime + size so it can be correlated with
    # XPX's xpx_export_log.txt — a write timestamp mismatch means
    # mkxp-z is reading a different copy than the one XPX wrote.
    begin
      sys_path = File.join(GAME_ROOT, "Data", "System.rxdata")
      if File.exist?(sys_path)
        st = File.stat(sys_path)
        log "System.rxdata: #{st.size} bytes, mtime=#{st.mtime.strftime('%Y-%m-%d %H:%M:%S')}"
        File.open(sys_path, "rb") do |f|
          sys_obj = Marshal.load(f)
          smid = (sys_obj.start_map_id rescue "<missing>")
          sx   = (sys_obj.start_x      rescue "<missing>")
          sy   = (sys_obj.start_y      rescue "<missing>")
          log "System.rxdata @start_map_id=#{smid} @start_x=#{sx} @start_y=#{sy}"
          if smid.is_a?(Integer) && smid == 0
            log "  ⚠ start_map_id==0 in System.rxdata — game will refuse to launch with this. XPX failed to write start position."
          end
        end
      else
        log "System.rxdata: NOT FOUND at #{sys_path}"
      end
    rescue => e
      log "System.rxdata audit failed: #{e.class}: #{e.message}"
    end
    # ── End ground-truth audit ───────────────────────────────────────────────

    return log("MAPS_DIR missing! Path: #{MAPS_DIR}") unless Dir.exist?(MAPS_DIR)
    index_maps
    log "Indexed #{($xpx_map_index||{}).size} maps"
    prewarm_map_dict_cache
    load_autotile_database
    patch_load_data
    log "load_data patched"
    install_data_maps_guard
    log "data_maps guard installed"
    patch_pbrgssexists
    log "pbRgssExists? patched"
    patch_compiler_safety
    log "compiler safety patched"
    # ── Event ID audit: verify start map events loaded with correct IDs ──────
    begin
      sys_start_id = ($data_system&.start_map_id rescue nil)
      audit_id = sys_start_id || ($xpx_map_index||{}).keys.min
      if audit_id
        audit_map = XPX.get_map(audit_id)
        if audit_map
          ev_summary = audit_map.events.map do |eid, ev|
            trigger = (ev.pages&.first&.trigger rescue "?")
            trigger_name = ["Action","Player Touch","Event Touch","Autorun","Parallel"][trigger] rescue trigger.to_s
            "#{eid}:#{ev.name}(#{trigger_name})"
          end.join(", ")
          log "Start map #{audit_id} has #{audit_map.events.size} events: #{ev_summary.empty? ? '(none)' : ev_summary}"
          # Specifically flag autorun events — these run the intro sequence
          autoruns = audit_map.events.select {|_, ev| ev.pages&.first&.trigger == 3 rescue false}
          if autoruns.empty?
            log "WARNING: No Autorun events on start map #{audit_id} — intro will not play"
          else
            log "Autorun events on start map: #{autoruns.map{|eid,ev| "#{eid}:#{ev.name}"}.join(', ')}"
          end
        else
          log "WARNING: Could not load start map #{audit_id} for audit"
        end
      end
    rescue => audit_err
      log "Event audit error: #{audit_err.message}"
    end
    log "Boot complete"
  rescue => e
    log "Boot ERROR: #{e.message}
#{e.backtrace.first(5).join('
')}"
  end


  # ── Fast index: only reads first 512 bytes per file ───────────────────────
  def self.index_maps
    $xpx_map_index ||= {}  # id => path
    $xpx_map_cache ||= {}  # id => RPG::Map (lazy)
    $xpx_map_infos ||= {}
    Dir.glob(File.join(MAPS_DIR, "*.xpxdata")).sort.each do |path|
      begin
        snippet = File.read(path, 512, encoding: "utf-8") rescue ""
        next unless (m = snippet.match(/"map_id"\s*:\s*(\d+)/))
        id = m[1].to_i
        $xpx_map_index[id] = path
        nm = (snippet.match(/"name"\s*:\s*"([^"]*)"/) rescue nil)
        info = RPG::MapInfo.new
        info.name = nm ? nm[1] : "Map#{id}"
        info.parent_id = 0; info.order = id
        $xpx_map_infos[id] = info
      rescue => e
        # skip bad files silently
      end
    end
  end

  # ── Pre-warm the map dict cache at boot ───────────────────────────────────
  # Reads + JSON-parses every map's xpxdata once at startup, stashing the
  # parsed dict in $xpx_map_dict_cache. Subsequent calls to get_map for
  # any map become a hash lookup + build_map (object construction only,
  # no IO).
  #
  # Why this exists: Pokémon Essentials's debug warp menu (and the
  # in-game F9 → "Visual Map Editor" / map list) enumerates every map
  # in the project to populate its UI. With 100+ maps it does 100+
  # synchronous load_data calls inside a single Ruby frame — never
  # yielding to Graphics.update — which trips RGSS's "Script is
  # hanging" watchdog (10s threshold). The user sees the menu hang
  # before painting and never recover.
  #
  # Pre-warming at boot moves that cost to a window the watchdog
  # tolerates: boot-time Ruby. Boot already does dozens of disk reads
  # for autotile DBs / system data; another 100-200 reads here is
  # measurable but not catastrophic — a few hundred ms on a project
  # with 171 maps. The user trades "instant boot, frozen menu" for
  # "1-2s slower boot, instant menu". Universally a better deal.
  #
  # Errors during prewarm are silent — a single corrupt xpxdata
  # shouldn't block boot. The map will just re-attempt the read on
  # next get_map call and surface the error there.
  def self.prewarm_map_dict_cache
    $xpx_map_dict_cache ||= {}
    return if $xpx_map_dict_cache.size > 0  # already warm (e.g. relaunch)
    return unless defined?(JSON)
    t0 = Time.now
    warmed = 0
    failed = 0
    ($xpx_map_index||{}).each do |id, path|
      begin
        raw = File.read(path, encoding: "utf-8")
        data = JSON.parse(raw) rescue nil
        if data
          $xpx_map_dict_cache[id] = data
          warmed += 1
        else
          failed += 1
        end
      rescue => e
        failed += 1
      end
    end
    elapsed_ms = ((Time.now - t0) * 1000).round
    log "Map dict cache pre-warmed: #{warmed} maps, #{failed} failed, #{elapsed_ms}ms"
  end

  # ── Lazy full map load ────────────────────────────────────────────────────
  #
  # TWO-LAYER CACHE for performance + correctness:
  #
  #   $xpx_map_cache[id]      → RPG::Map instance (the built object).
  #                              Evicted on Game_Map#setup so each
  #                              map entry gets a fresh instance
  #                              (prevents plugin mutations from
  #                              persisting across transfers — see
  #                              the eviction comment in
  #                              _xpx_install_game_map_setup_wrap).
  #
  #   $xpx_map_dict_cache[id] → parsed JSON dict (the file contents).
  #                              NOT evicted on setup. The xpxdata
  #                              file only changes when XPX writes a
  #                              new save out-of-band; within a game
  #                              session it's stable, so caching the
  #                              parse result is safe and saves the
  #                              multi-MB File.read + JSON.parse on
  #                              every map switch.
  #
  # This split fixes a freeze in Essentials's debug-menu warp: the
  # menu cycles through Game_Map#setup rapidly enough that re-
  # parsing the full xpxdata file on every call cumulatively blew
  # past RGSS's 10-second script-watchdog. With the dict cache,
  # repeated entries to the same map become a hash lookup +
  # build_map (which is just object construction, no IO).
  def self.get_map(id)
    $xpx_map_cache      ||= {}
    $xpx_map_dict_cache ||= {}
    return $xpx_map_cache[id] if $xpx_map_cache[id]

    # ── Variant resolution ──────────────────────────────────────
    # Each map's xpxdata can carry a `variants` list. The runtime
    # checks each variant's condition (switch/variable) in priority
    # order; the FIRST match's xpxdata is loaded instead of the
    # base. The returned RPG::Map keeps the requested `id` as its
    # logical map_id, so events/scripts referencing the parent map
    # still resolve correctly. Internally each variant is a
    # separate xpxdata file (its own tile data, events, tileset),
    # so swapping is just "load a different file under the same
    # logical id".
    effective_id = resolve_variant_id(id)
    load_path = ($xpx_map_index||{})[effective_id] ||
                ($xpx_map_index||{})[id]
    return nil unless load_path

    begin
      # Dict cache lookup — keyed by effective_id so a variant swap
      # gets its own dict slot. Cache key includes the resolved
      # path so a future "variant changed" path could invalidate
      # cleanly if needed.
      data = $xpx_map_dict_cache[effective_id]
      if data.nil?
        raw = File.read(load_path, encoding: "utf-8")
        # If json stdlib failed to load, the xpxdata path silently
        # no-ops and the caller falls back to the rxdata reader.
        data = defined?(JSON) ? (JSON.parse(raw) rescue nil) : nil
        return nil unless data
        $xpx_map_dict_cache[effective_id] = data
      end

      m = build_map(data)
      # Track which variant (or base) is currently realised under
      # the requested id, so the per-frame check in
      # check_variant_swap can detect when to re-load.
      $xpx_active_variant ||= {}
      $xpx_active_variant[id] = effective_id
      if effective_id != id
        xpx_puts "Map#{id}: loaded variant #{effective_id} (#{data['name']})"
      end
      $xpx_map_cache[id] = m
    rescue => e
      xpx_puts "Map#{id} load error: #{e.message}"
      nil
    end
  end

  # ── Variant condition evaluation ─────────────────────────────────────
  # CRITICAL perf path: the per-frame Scene_Map#update wrap calls
  # this on every tick (60 times per second). Reading + JSON-parsing
  # the parent's xpxdata file (which can be MBs for big maps) every
  # frame stalls the editor — that's what was causing the "very
  # laggy map changes" + the "warp to map freezes" symptoms. The
  # debug-menu warp ran a tight Game_Map.setup loop while inside
  # the debug interpreter, and each setup re-triggered the per-frame
  # check, each check re-read the file…
  #
  # Fix: cache the variants-list (and the parent's cols/rows for
  # the size-invariant check) per parent_id on first access. The
  # underlying xpxdata only changes when XPX writes it, which
  # happens out-of-band from the runtime — caching is safe for the
  # entire game session. `index_maps` already runs once at boot to
  # build $xpx_map_index; we use the same idiom (lazy-fill on first
  # access, never invalidate during the session).
  def self._variant_rules_for(parent_id)
    $xpx_variant_rules ||= {}   # parent_id => Hash or :none
    cached = $xpx_variant_rules[parent_id]
    return cached unless cached.nil?
    path = ($xpx_map_index||{})[parent_id]
    unless path
      $xpx_variant_rules[parent_id] = :none
      return :none
    end
    begin
      raw = File.read(path, encoding: "utf-8")
      data = defined?(JSON) ? (JSON.parse(raw) rescue nil) : nil
    rescue
      data = nil
    end
    if !data || !data["variants"].is_a?(Array) || data["variants"].empty?
      $xpx_variant_rules[parent_id] = :none
      return :none
    end
    rules = {
      "variants" => data["variants"],
      "cols"     => (data["cols"]||0).to_i,
      "rows"     => (data["rows"]||0).to_i,
    }
    $xpx_variant_rules[parent_id] = rules
    rules
  end

  # Variant size-mismatch check is also cached per variant id so we
  # don't keep re-reading the variant's xpxdata header to confirm
  # its dimensions match the parent's. Same lifetime as the variant
  # rules cache — stays valid for the session.
  def self._variant_size_ok?(parent_id, variant_id, parent_cols, parent_rows)
    $xpx_variant_size_ok ||= {}
    key = "#{parent_id}/#{variant_id}"
    cached = $xpx_variant_size_ok[key]
    return cached unless cached.nil?
    vpath = ($xpx_map_index||{})[variant_id]
    unless vpath
      $xpx_variant_size_ok[key] = false
      return false
    end
    snip = (File.read(vpath, 512, encoding: "utf-8") rescue "")
    vc = (snip.match(/"cols"\s*:\s*(\d+)/) rescue nil)
    vr = (snip.match(/"rows"\s*:\s*(\d+)/) rescue nil)
    if vc && vr && parent_cols > 0 && parent_rows > 0
      ok = (vc[1].to_i == parent_cols && vr[1].to_i == parent_rows)
      unless ok
        xpx_puts "Variant #{variant_id} of Map#{parent_id} has " \
                 "size mismatch (#{vc[1]}x#{vr[1]} vs " \
                 "parent #{parent_cols}x#{parent_rows}) — skipped"
      end
      $xpx_variant_size_ok[key] = ok
      ok
    else
      $xpx_variant_size_ok[key] = true   # benefit of doubt
      true
    end
  end

  def self.resolve_variant_id(parent_id)
    rules = _variant_rules_for(parent_id)
    return parent_id if rules == :none
    pcols = rules["cols"]
    prows = rules["rows"]
    rules["variants"].each do |v|
      next unless v.is_a?(Hash)
      next unless variant_condition_matches?(v)
      vid = (v["variant_map_id"]||0).to_i
      next if vid <= 0
      next unless _variant_size_ok?(parent_id, vid, pcols, prows)
      return vid
    end
    parent_id
  rescue => e
    xpx_puts "resolve_variant_id error for Map#{parent_id}: #{e.message}"
    parent_id
  end

  # Evaluate a single variant's condition against the live game
  # state. Returns true iff the condition matches right now.
  def self.variant_condition_matches?(v)
    return false unless v.is_a?(Hash)
    ctype = (v["condition_type"]||"").to_s
    case ctype
    when "switch"
      sid = (v["condition_id"]||0).to_i
      return false if sid <= 0
      want_op = (v["condition_op"]||"ON").to_s
      cur = ($game_switches[sid] rescue false)
      return cur ? (want_op == "ON") : (want_op == "OFF")
    when "variable"
      vid = (v["condition_id"]||0).to_i
      return false if vid <= 0
      target = (v["condition_val"]||0).to_i
      cur = ($game_variables[vid].to_i rescue 0)
      op = (v["condition_op"]||"==").to_s
      case op
      when "==" then return cur == target
      when "!=" then return cur != target
      when ">"  then return cur >  target
      when "<"  then return cur <  target
      when ">=" then return cur >= target
      when "<=" then return cur <= target
      else return false
      end
    end
    false
  end

  # Per-frame check (called from a Scene_Map#update wrap further down
  # in this preload). Decides whether the currently-loaded variant
  # is still the right one given the live game state, and triggers a
  # transfer back to "the same map" (which re-runs get_map and picks
  # up the new variant) when it isn't.
  def self.check_variant_swap
    return unless $game_map && $game_player
    cur_map_id = $game_map.map_id rescue nil
    return unless cur_map_id

    # Don't yank the map mid-cutscene. Five guards, all of which
    # need to be CLEAR before we'll trigger a swap:
    #   - message window open (text waiting for the player)
    #   - move route forcing (event scripted movement)
    #   - autorun / parallel interpreter running ($game_system
    #     .map_interpreter is the autorun runner; if it's busy we
    #     wait until it finishes)
    #   - already transferring (we're mid-fade ourselves)
    #   - in a battle (Scene_Battle is active, not Scene_Map)
    return if $game_temp && $game_temp.message_window_showing
    return if $game_player.move_route_forcing
    if $game_system && $game_system.map_interpreter &&
       $game_system.map_interpreter.respond_to?(:running?)
      return if $game_system.map_interpreter.running?
    end
    return if $game_temp && $game_temp.player_transferring
    # Scene check — only run on Scene_Map (per-frame hook installs
    # there, but Pokémon Essentials sometimes pushes a sub-scene that
    # inherits Scene_Map; we still want to wait for that to clear).
    return unless $scene && $scene.is_a?(Scene_Map)

    # Compare what's loaded vs what should be loaded.
    $xpx_active_variant ||= {}
    currently_loaded = $xpx_active_variant[cur_map_id] || cur_map_id
    target_id = resolve_variant_id(cur_map_id)
    return if target_id == currently_loaded   # no change

    xpx_puts "Variant flip on Map#{cur_map_id}: #{currently_loaded} -> #{target_id}; transferring."

    # Trigger a same-map transfer. We use RGSS's standard
    # transfer-processing flag so the Scene_Map fade machinery
    # handles the fade-out / fade-in for us — no custom Graphics.freeze
    # / transition timing needed. The transfer target is the SAME
    # logical map_id; we evict our cache so get_map() re-resolves
    # the now-active variant when Game_Map.setup runs.
    px  = $game_player.x
    py  = $game_player.y
    pdir = $game_player.direction
    if $xpx_map_cache && $xpx_map_cache.is_a?(Hash)
      $xpx_map_cache.delete(cur_map_id)
    end
    if $data_maps && $data_maps.is_a?(Hash)
      $data_maps.delete(cur_map_id) rescue nil
    end
    $game_temp.player_new_map_id     = cur_map_id
    $game_temp.player_new_x          = px
    $game_temp.player_new_y          = py
    $game_temp.player_new_direction  = pdir
    $game_temp.transition_processing = true
    $game_temp.player_transferring   = true
  end

  # ── Autotile pattern lookup (v21-aligned) ──────────────────────────────
  # XPX stores `at_frame: 0` for every autotile cell in the map data —
  # the actual pattern (corner/edge/interior config) is computed at
  # render time. v21's TilemapRenderer expects pattern baked INTO the
  # tile_id (`tile_id = 48 + slot*48 + pattern`), so build_map has to
  # compute the pattern from neighbours just like the editor's canvas
  # does at paint time.
  #
  # NEIGHBORS_TO_AUTOTILE_INDEX is v21's canonical 256-entry mask →
  # pattern lookup table from TileDrawingHelper.rb. Bit ordering:
  #   0x01=N  0x02=NE  0x04=E  0x08=SE  0x10=S  0x20=SW  0x40=W  0x80=NW
  NEIGHBORS_TO_AUTOTILE_INDEX = [
    46, 44, 46, 44, 43, 41, 43, 40, 46, 44, 46, 44, 43, 41, 43, 40,
    42, 32, 42, 32, 35, 19, 35, 18, 42, 32, 42, 32, 34, 17, 34, 16,
    46, 44, 46, 44, 43, 41, 43, 40, 46, 44, 46, 44, 43, 41, 43, 40,
    42, 32, 42, 32, 35, 19, 35, 18, 42, 32, 42, 32, 34, 17, 34, 16,
    45, 39, 45, 39, 33, 31, 33, 29, 45, 39, 45, 39, 33, 31, 33, 29,
    37, 27, 37, 27, 23, 15, 23, 13, 37, 27, 37, 27, 22, 11, 22,  9,
    45, 39, 45, 39, 33, 31, 33, 29, 45, 39, 45, 39, 33, 31, 33, 29,
    36, 26, 36, 26, 21,  7, 21,  5, 36, 26, 36, 26, 20,  3, 20,  1,
    46, 44, 46, 44, 43, 41, 43, 40, 46, 44, 46, 44, 43, 41, 43, 40,
    42, 32, 42, 32, 35, 19, 35, 18, 42, 32, 42, 32, 34, 17, 34, 16,
    46, 44, 46, 44, 43, 41, 43, 40, 46, 44, 46, 44, 43, 41, 43, 40,
    42, 32, 42, 32, 35, 19, 35, 18, 42, 32, 42, 32, 34, 17, 34, 16,
    45, 38, 45, 38, 33, 30, 33, 28, 45, 38, 45, 38, 33, 30, 33, 28,
    37, 25, 37, 25, 23, 14, 23, 12, 37, 25, 37, 25, 22, 10, 22,  8,
    45, 38, 45, 38, 33, 30, 33, 28, 45, 38, 45, 38, 33, 30, 33, 28,
    36, 24, 36, 24, 21,  6, 21,  4, 36, 24, 36, 24, 20,  2, 20,  0
  ].freeze

  # Compute v21-style autotile neighbour mask. Looks at 8 neighbours
  # of the same layer; each bit is set iff that neighbour is an
  # autotile cell of the same `slot`. Out-of-bounds neighbours are
  # treated as same-slot (matches v21's tableNeighbors clamp behaviour
  # via `data[xp1, ym1]` with clamped coords; effectively means edges
  # extend outwards rather than break the autotile pattern).
  def self.autotile_neighbour_mask(lrows, x, y, slot, cols, rows)
    mask = 0
    [
      [0x01,  0, -1],  # N
      [0x02,  1, -1],  # NE
      [0x04,  1,  0],  # E
      [0x08,  1,  1],  # SE
      [0x10,  0,  1],  # S
      [0x20, -1,  1],  # SW
      [0x40, -1,  0],  # W
      [0x80, -1, -1],  # NW
    ].each do |bit, dx, dy|
      nx = x + dx
      ny = y + dy
      if nx < 0 || nx >= cols || ny < 0 || ny >= rows
        # Off-map: v21 clamps to edge so a corner cell sees its own
        # tile as the neighbour; we mirror that by treating OOB as
        # same-slot. Without this, all map-edge autotile cells would
        # render as outer-corner patterns even when the user filled
        # them in to form a flush edge.
        mask |= bit
        next
      end
      nrow = lrows[ny]
      next unless nrow.is_a?(Array)
      ncell = nrow[nx]
      next unless ncell.is_a?(Hash)
      n_at = ncell["autotile"]
      mask |= bit if !n_at.nil? && n_at.to_i == slot
    end
    mask
  end

  # ── Build RPG::Map from xpxdata dict ─────────────────────────────────────
  def self.build_map(d)
    cols = (d["cols"]||20).to_i; rows = (d["rows"]||15).to_i
    layers_data = d["layers"]||[]
    depth = [layers_data.size, 3].max   # Support N layers
    m = RPG::Map.new(cols, rows)
    m.tileset_id   = (d["tileset_id"]||1).to_i rescue 1
    m.autoplay_bgm = !!d["bgm_name"] && d["bgm_name"] != ""
    m.bgm = RPG::AudioFile.new(d["bgm_name"]||"", 100, 100)
    m.data = Table.new(cols, rows, depth)

    # ── Per-map autotile assignment ─────────────────────────────────
    # XPX stores autotiles per-MAP, not per-tileset. Each map's
    # `autotile_paths` is its own ordered slot list (slots 0-6 are
    # the legacy 7 RGSS slots, 7+ are extended autotiles routed via
    # v21's EXTRA_AUTOTILES system).
    #
    # RPG::Map has NO autotile_names attribute — that lives on
    # RPG::Tileset. The renderer reads from $data_tilesets[tid]
    # .autotile_names. So we stash all per-map data in globals,
    # and the Game_Map.setup wrap mirrors them into the tileset
    # right before Spriteset_Map.new fires.
    #
    # Build:
    #   - $xpx_map_extras[map_id]["legacy"] = 7-slot legacy name array
    #   - $xpx_map_extras[map_id]["large"]  = extended large autotile names
    #   - $xpx_map_extras[map_id]["single"] = extended single autotile names
    #   - $xpx_extra_slot_translation[map_id] = slot to (kind, pos) hash
    #     for build_map's autotile cell encoding (below)
    #
    # All keyed by map_id (not tileset_id) because two maps sharing
    # the same tileset can have completely different autotile sets
    # in XPX. The setup wrap swaps tileset autotile_names + the v21
    # EXTRA_AUTOTILES hash per transfer to keep v21's renderer happy.
    map_id_for_keys = (d["map_id"]||0).to_i
    autotile_paths  = d["autotile_paths"] || []
    legacy_names = (0..6).map do |i|
      ap = autotile_paths[i]
      ap ? File.basename(ap.to_s, File.extname(ap.to_s)) : ""
    end

    # Slots 7+: classify large vs single. Decision order MUST match
    # the editor's mkxpz_exporter._classify_autotile_layout, otherwise
    # editor and runtime disagree on EXTRA_AUTOTILES layout and the
    # tile_id encoding produced by build_map points at the wrong
    # autotile. The editor's order is:
    #   1. DB entry's frame_layout, if explicitly set
    #      ("single_row_32px" → single, "horizontal_96px" → large)
    #   2. Image height: 32 → single, else → large
    #   3. Default → large
    # Almost all DB entries leave frame_layout as nil (autodetect), so
    # step 2 is the common path. We cache per-filename to avoid loading
    # each PNG more than once across the 171 maps × ~14 slots.
    large_names  = []
    single_names = []
    slot_table   = {}
    large_idx    = 0
    single_idx   = 0
    autotile_paths.each_with_index do |ap, slot|
      next if slot < 7 || ap.nil? || ap.to_s.empty?
      fname  = File.basename(ap.to_s, File.extname(ap.to_s))
      kind   = XPX.classify_autotile_kind(fname)
      if kind == "single"
        single_names << fname
        slot_table[slot] = ["single", single_idx]
        single_idx += 1
      else
        large_names << fname
        slot_table[slot] = ["large", large_idx]
        large_idx += 1
      end
    end
    # v21 shifts the boundary between "extra autotile" and "tileset
    # tile" up by (large_count*48 + single_count) when EXTRA_AUTOTILES
    # has entries. Tileset cells encoded as `384 + tr*8 + tc` collide
    # with extra-autotile slots when a map uses 7+ autotiles; we have
    # to bake the shift into the cell encoding so the renderer reads
    # the right region.
    extras_shift = large_names.length * 48 + single_names.length
    $xpx_extra_slot_translation ||= {}
    $xpx_extra_slot_translation[map_id_for_keys] = slot_table
    $xpx_extra_slot_meta ||= {}
    $xpx_extra_slot_meta[map_id_for_keys] = { "large_count" => large_names.length }
    $xpx_map_extras ||= {}
    $xpx_map_extras[map_id_for_keys] = {
      "legacy" => legacy_names,
      "large"  => large_names,
      "single" => single_names,
    }
    layers_data.each_with_index do |lrows, z|
      next unless lrows.is_a?(Array)
      lrows.each_with_index do |row, y|
        next unless row.is_a?(Array)
        row.each_with_index do |cell, x|
          next unless cell.is_a?(Hash)
          if cell["autotile"]
            slot = (cell["autotile"]||0).to_i
            # Compute pattern (0..47) from neighbours. XPX always
            # writes at_frame=0 in saved data — the editor recomputes
            # the pattern at canvas render time from neighbours, but
            # never persists it. v21 expects the pattern baked into
            # the tile_id, so we have to do the same job here.
            pattern = NEIGHBORS_TO_AUTOTILE_INDEX[
              autotile_neighbour_mask(lrows, x, y, slot, cols, rows)
            ]
            # Slots 0-6: standard RGSS encoding. tile_id = 48 + slot*48 + pat.
            # Slots 7+: extended autotiles (v21's EXTRA_AUTOTILES).
            #   - large extras: tile_id 384 + pos*48 + pat
            #   - single extras: tile_id 384 + (large_count*48) + pos
            #     (no patterns; one id per autotile, animation-only)
            if slot <= 6
              m.data[x,y,z] = 48 + slot*48 + pattern
            else
              tbl  = ($xpx_extra_slot_translation || {})[map_id_for_keys]
              meta = ($xpx_extra_slot_meta        || {})[map_id_for_keys] || {}
              kind_pos = tbl && tbl[slot]
              if kind_pos
                kind, pos = kind_pos
                if kind == "large"
                  m.data[x,y,z] = 384 + pos*48 + pattern
                else
                  # single autotiles have no pattern variants
                  large_count = (meta["large_count"] || 0).to_i
                  m.data[x,y,z] = 384 + large_count*48 + pos
                end
              else
                # Unreachable in normal flow — falls back to a sane
                # default if the slot table is somehow incomplete.
                m.data[x,y,z] = 48 + slot*48 + pattern
              end
            end
          else
            # Tileset cell. v21's tileset region starts at TILESET_START_ID
            # (384) when EXTRA_AUTOTILES[tid] is empty, but shifts up by
            # large_count*48 + single_count when the map uses extras.
            # Without this shift, tileset cells collide with extra-autotile
            # ids and the whole map renders as the first extra autotile.
            tc = (cell["tc"]||0).to_i; tr = (cell["tr"]||0).to_i
            m.data[x,y,z] = 384 + extras_shift + tr*8 + tc
          end
        end
      end
    end
    m.events = {}
    used_eids = {}
    missing_id_count = 0
    # First pass: collect all preserved IDs to avoid collisions in fallback
    ((d["events"]||{}).is_a?(Hash) ? d["events"] : {}).each do |key, ev|
      next unless ev.is_a?(Hash)
      pid = ev["id"]
      used_eids[pid.to_i] = true if pid.is_a?(Integer) && pid >= 1 && pid <= 9999
    end
    ev_counter = 1
    ((d["events"]||{}).is_a?(Hash) ? d["events"] : {}).each do |key, ev|
      next unless ev.is_a?(Hash)
      ex = (ev["x"]||0).to_i; ey = (ev["y"]||0).to_i
      # Use the original RMXP ID if preserved; otherwise find the next free slot.
      # Essentials looks up events by ID for self-switches, trainer data, autorun
      # triggers, and get_character(N) — a wrong ID silently breaks all of these.
      #
      # IDs SHOULD always be preserved by the editor (see save_manager + map_io
      # validation). The fallback below exists only as a last-resort safety net
      # for legacy .xpxdata files written before the editor enforced ID
      # preservation. We log every missing-ID case so authors hitting this
      # path (which means their event lookups by ID may shift across reloads)
      # see a clear warning rather than silently broken self-switches and
      # trainer data.
      pid = ev["id"]
      if pid.is_a?(Integer) && pid >= 1 && pid <= 9999
        eid = pid
      else
        ev_counter += 1 while used_eids[ev_counter]
        eid = ev_counter
        used_eids[eid] = true
        ev_counter += 1
        missing_id_count += 1
      end
      pages = ((ev["pages"]||[]).is_a?(Array) ? ev["pages"] : []).map {|p| build_page(p)}
      pages = [RPG::Event::Page.new] if pages.empty?
      pages.each {|pg| ensure_page_valid(pg)}
      e = RPG::Event.new(ex, ey)
      e.id = eid; e.name = (ev["name"]||"EV").to_s.strip
      e.pages = pages
      m.events[eid] = e
    end
    if missing_id_count > 0
      log "Map id=#{(d['map_id']||'?')}: WARNING #{missing_id_count} event(s) had no preserved ID — auto-assigned. "           "Self-switches / trainer lookups / get_character(N) calls referencing those events may behave unpredictably across reloads. "           "Re-save the map in the editor (the editor now enforces ID preservation) to fix permanently."
    end
    m
  end

  # ── Ensure every page field is non-nil ───────────────────────────────────
  def self.ensure_page_valid(pg)
    return unless pg
    pg.condition  ||= RPG::Event::Page::Condition.new
    pg.graphic    ||= RPG::Event::Page::Graphic.new
    pg.move_route ||= RPG::MoveRoute.new
    unless pg.list.is_a?(Array) && !pg.list.empty?
      t = RPG::EventCommand.new; t.code = 0
      pg.list = [t]
    end
    unless pg.list.last.is_a?(RPG::EventCommand) && pg.list.last.code == 0
      t = RPG::EventCommand.new; t.code = 0
      pg.list << t
    end
    pg.list.each do |cmd|
      next unless cmd.is_a?(RPG::EventCommand)
      cmd.parameters ||= []
      cmd.parameters = [] unless cmd.parameters.is_a?(Array)
      # Ensure Show Text (101) and similar string-param commands never have nil params[0]
      if [101, 401, 355, 655, 108, 408].include?(cmd.code)
        cmd.parameters[0] = "" if cmd.parameters[0].nil?
        cmd.parameters[0] = cmd.parameters[0].to_s if !cmd.parameters[0].is_a?(String)
      end
      # Set Move Route (209): parameters[1] must be RPG::MoveRoute not Hash
      if cmd.code == 209 && cmd.parameters.size > 1 && cmd.parameters[1].is_a?(Hash)
        cmd.parameters[1] = XPX.build_move_route(cmd.parameters[1])
      end rescue nil
      # Audio commands: parameters[0] must be RPG::AudioFile not Hash
      if [132, 133, 241, 243, 247, 248].include?(cmd.code) && cmd.parameters.size > 0
        cmd.parameters[0] = XPX.build_audio_file(cmd.parameters[0]) if cmd.parameters[0].is_a?(Hash) || cmd.parameters[0].is_a?(String)
      end rescue nil
      # Screen Color Tone (223): parameters[0] must be Tone not Hash
      if cmd.code == 223 && cmd.parameters.size > 0 && cmd.parameters[0].is_a?(Hash)
        cmd.parameters[0] = XPX.build_tone(cmd.parameters[0])
      end rescue nil
      # Flash Screen (224): parameters[0] must be Color not Hash
      if cmd.code == 224 && cmd.parameters.size > 0 && cmd.parameters[0].is_a?(Hash)
        cmd.parameters[0] = XPX.build_color(cmd.parameters[0])
      end rescue nil
    end
    pg
  end

  # ── Build a single event page ─────────────────────────────────────────────
  def self.build_page(p)
    pg = RPG::Event::Page.new
    return ensure_page_valid(pg) unless p.is_a?(Hash)
    pg.trigger = {"Action Button"=>0,"Player Touch"=>1,
                   "Event Touch"=>2,"Autorun"=>3,
                   "Parallel Process"=>4}[p["trigger"]||"Action Button"]||0

    # ── Conditions ──────────────────────────────────────────────────────
    cond = RPG::Event::Page::Condition.new
    if p["condition_switch"]
      cond.switch1_valid = true
      cond.switch1_id    = (p["condition_switch"].to_i rescue 1)
      # XPX-only: switch ON/OFF state. RMXP's runtime hard-codes
      # the test to "is ON". We stash the desired state as an ivar
      # and let the Game_Event#refresh patch (loaded by
      # XPX_Preload.rb) flip the meaning when state=false (OFF).
      # Default true == RMXP-compatible behaviour.
      sw_state = p.has_key?("condition_switch_state") ? !!p["condition_switch_state"] : true
      cond.instance_variable_set(:@xpx_switch1_state, sw_state)
    end
    if p["condition_switch2"]
      cond.switch2_valid = true
      cond.switch2_id    = (p["condition_switch2"].to_i rescue 1)
      # Switch 2 OFF-state extension — symmetrical with Switch 1.
      # RMXP hard-codes both Switch slots to "must be ON"; XPX
      # extends both to allow "must be OFF" via @xpx_switchN_state.
      # Default true == RMXP-compatible.
      sw2_state = p.has_key?("condition_switch2_state") ? !!p["condition_switch2_state"] : true
      cond.instance_variable_set(:@xpx_switch2_state, sw2_state)
    end
    # Variable page-condition: $game_variables[id] OP value. RMXP's
    # vanilla runtime hard-codes OP to >=, but the XPX editor lets
    # users pick from the full set (==, >=, <=, >, <, !=). For ops
    # other than >= we still set @variable_id / @variable_value so
    # the page activates on the >= path AND attach a custom
    # @xpx_variable_operator ivar that the runtime patch (loaded at
    # boot via XPX_Preload.rb) reads to enforce the user's chosen
    # comparison.
    #
    # Op encoding: 0===, 1=>=, 2=<=, 3=>, 4=<, 5=!=
    var_cond = p["condition_variable_id"] || p["condition_variable"]
    if var_cond
      cond.variable_valid = true
      cond.variable_id    = (var_cond.to_i rescue 1)
      cond.variable_value = (p["condition_variable_value"].to_i rescue 0)
      var_op = (p["condition_variable_operator"].to_i rescue 1)
      cond.instance_variable_set(:@xpx_variable_operator, var_op)
    end
    if p["condition_self_switch"]
      cond.self_switch_valid = true
      cond.self_switch_ch    = p["condition_self_switch"].to_s
    end
    pg.condition = cond

    # ── Graphic ─────────────────────────────────────────────────────────
    # Without this block every event renders as an invisible blank — the
    # default RPG::Event::Page::Graphic has @character_name='' and
    # @tile_id=0. Read the full graphic dict if present (imported events
    # preserve every field), fall back to graphic_name string for legacy
    # xpxdata that pre-dated full-dict capture.
    g = RPG::Event::Page::Graphic.new
    g_dict = p["graphic"]
    if g_dict.is_a?(Hash)
      g.tile_id        = (g_dict["tile_id"]||0).to_i
      g.character_name = (g_dict["character_name"] || p["graphic_name"] || "").to_s
      g.character_hue  = (g_dict["character_hue"]||0).to_i
      g.direction      = (g_dict["direction"]||2).to_i
      g.pattern        = (g_dict["pattern"]||0).to_i
      g.opacity        = (g_dict["opacity"]||255).to_i
      g.blend_type     = (g_dict["blend_type"]||0).to_i
    else
      # Legacy / new-XPX events that only have graphic_name
      g.character_name = (p["graphic_name"]||"").to_s
      g.direction      = 2
      g.opacity        = 255
    end
    pg.graphic = g

    # ── Movement / animation / passability flags ────────────────────────
    # Every one of these defaults to a non-trivial value in RMXP, and
    # missing them means imported events behave wrong: walk-through
    # decoration events become solid blockers, autorun events get the
    # wrong move_type, NPCs stop animating, etc.
    pg.move_type      = (p["move_type"]||0).to_i
    pg.move_speed     = (p["move_speed"]||3).to_i
    pg.move_frequency = (p["move_frequency"]||3).to_i
    pg.walk_anime     = p.has_key?("walk_anime")    ? !!p["walk_anime"]    : true
    pg.step_anime     = p.has_key?("step_anime")    ? !!p["step_anime"]    : false
    pg.direction_fix  = p.has_key?("direction_fix") ? !!p["direction_fix"] : false
    pg.through        = p.has_key?("through")       ? !!p["through"]       : false
    pg.always_on_top  = p.has_key?("always_on_top") ? !!p["always_on_top"] : false
    mr_dict = p["move_route"]
    pg.move_route = mr_dict.is_a?(Hash) ? XPX.build_move_route(mr_dict) : RPG::MoveRoute.new
    raw_cmds = p["commands"].is_a?(Array) ? p["commands"] : []
    cmds = raw_cmds.filter_map do |cmd|
      next nil unless cmd.is_a?(Hash)
      c2 = RPG::EventCommand.new

      # Branch on rmxp_raw flag:
      #   true  → command is in raw RMXP format (code + parameters)
      #           — happens for events imported from Essentials
      #   false → command is in XPX-native format (cmd_type + params)
      #           — happens for events authored in XPX's event editor
      # Either way we end up with c2.code + c2.parameters in raw RMXP
      # shape, since RPG::Interpreter only knows how to read that.
      if cmd["rmxp_raw"] == false
        # XPX-native command: translate cmd_type + params back to RMXP.
        # CommandTranslator.translate populates code/indent/parameters
        # in-place on c2 so we don't have to special-case the audio /
        # tone / color / move-route fixups below — the translator
        # produces correctly-shaped parameters from the start.
        XPX::CommandTranslator.translate(cmd, c2)
      else
        c2.code       = ((cmd["code"]||0).to_i rescue 0)
        c2.indent     = ((cmd["indent"]||0).to_i rescue 0)
        plist = cmd["parameters"]
        c2.parameters = plist.is_a?(Array) ? plist.map{|x| x.nil? ? "" : x} : []
      end

      # Fixups below apply to both code paths — they coerce dict-shaped
      # parameters into proper RPG::* objects. The translator emits
      # already-correct objects so these become no-ops for native
      # commands; raw RMXP imports may still have Hash leftovers from
      # JSON round-tripping that need fixing.
      if [101, 401, 355, 655, 108, 408].include?(c2.code)
        c2.parameters[0] = "" if c2.parameters.empty? || c2.parameters[0].nil?
        c2.parameters[0] = c2.parameters[0].to_s rescue ""
      end
      if c2.code == 209 && c2.parameters.size > 1 && c2.parameters[1].is_a?(Hash)
        c2.parameters[1] = XPX.build_move_route(c2.parameters[1])
      end
      if [241, 245, 246, 247, 249, 250, 238, 132].include?(c2.code) && c2.parameters.size > 0
        c2.parameters[0] = XPX.build_audio_file(c2.parameters[0]) if c2.parameters[0].is_a?(Hash) || c2.parameters[0].is_a?(String)
      end rescue nil
      if c2.code == 223 && c2.parameters.size > 0 && c2.parameters[0].is_a?(Hash)
        c2.parameters[0] = XPX.build_tone(c2.parameters[0])
      end rescue nil
      if c2.code == 224 && c2.parameters.size > 0 && c2.parameters[0].is_a?(Hash)
        c2.parameters[0] = XPX.build_color(c2.parameters[0])
      end rescue nil
      c2
    end
    t = RPG::EventCommand.new; t.code = 0
    cmds << t unless cmds.last&.code == 0
    pg.list = cmds
    mr = RPG::MoveRoute.new
    if (mr_data = p["move_route"]).is_a?(Hash)
      mr.repeat    = mr_data["repeat"] != false
      mr.skippable = !!mr_data["skippable"]
      mc_list = (mr_data["list"]||[]).is_a?(Array) ? mr_data["list"] : []
      mc_cmds = mc_list.filter_map do |mc|
        next nil unless mc.is_a?(Hash)
        m2 = RPG::MoveCommand.new
        m2.code = ((mc["code"]||0).to_i rescue 0)
        m2.parameters = (mc["parameters"]||[]).is_a?(Array) ? mc["parameters"] : []
        m2
      end
      t2 = RPG::MoveCommand.new; t2.code = 0
      mc_cmds << t2 unless mc_cmds.last&.code == 0
      mr.list = mc_cmds
    end
    pg.move_route = mr
    ensure_page_valid(pg)
  end

  def self.empty_map
    m = RPG::Map.new(20, 15)
    m.events = {}
    m
  end

  # ── Native .xpxdata loaders (Phase 1) ────────────────────────────────────
  #
  # These build native RPG::* objects from XPX's JSON sidecars, so the
  # runtime can serve XPX-canonical data without round-tripping through
  # rxdata. Each loader returns nil when its sidecar is missing or
  # unparseable — callers fall back to the rxdata path in that case,
  # so projects that haven't been re-exported by the editor still work.
  #
  # Coverage today:
  #   • CommonEvents — full xpxdata replacement (XPX_CommonEvents.json)
  #   • System       — xpxdata OVERLAY on top of rxdata (xpxdata is
  #                    canonical for start position / switches /
  #                    variables; rxdata still supplies audio / UI
  #                    defaults that the editor doesn't model yet)
  #   • MapInfos     — xpxdata replacement (XPX_MapInfos.json, already
  #                    populated into $xpx_map_infos at boot)
  #
  # Coverage NOT yet here:
  #   • Tilesets — written directly to Tilesets.rxdata by the editor's
  #                tileset_export.py, so rxdata IS the canonical store.
  #                No xpxdata loader needed.
  #   • Scripts  — Marshal-format Scripts.rxdata stays canonical for
  #                this round; xpxdata Scripts conversion is Phase 2
  #                (needs Zlib deflation to match the rxdata wire format).

  # Return parsed JSON from a project-relative Data sidecar, or nil if
  # the file's missing / unparseable. Centralised so every loader gets
  # the same encoding + error handling treatment.
  #
  # Phase 3 (xpxdata branding): callers historically passed
  # "XPX_System.json" etc. The on-disk file is now written with a
  # `.xpxdata` extension for consistency with Map###.xpxdata and the
  # rest of the editor's terminology. We try `.xpxdata` first, fall
  # back to `.json` so projects exported BEFORE the rename keep
  # working until they're re-saved (at which point the editor writes
  # `.xpxdata` and the `.json` variant becomes inert).
  def self._load_json_sidecar(filename)
    return nil unless defined?(JSON)
    # Strip whatever extension the caller passed and try .xpxdata, .json
    # in that priority order. Both contain the same JSON content; only
    # the file extension differs.
    base = filename.sub(/\.(?:json|xpxdata)$/i, "")
    candidates = ["#{base}.xpxdata", "#{base}.json"]
    candidates.each do |fname|
      path = File.join(GAME_ROOT, "Data", fname)
      next unless File.exist?(path)
      begin
        raw = File.read(path, encoding: "utf-8")
        return JSON.parse(raw)
      rescue => e
        log "JSON sidecar #{fname} parse error: #{e.message}"
        # Fall through to the next candidate rather than giving up
        # — a corrupt .xpxdata still has a chance of recovering from
        # an older .json sibling.
      end
    end
    nil
  end

  # Build an Array<RPG::EventCommand> from raw command dicts in xpxdata
  # form. Extracted from build_page so common events can use the same
  # logic without copy-paste drift. Mirrors the per-command translation
  # rules (XPX-native vs rmxp_raw, audio/move/tone/color coercion).
  def self.build_command_list(raw_cmds)
    raw_cmds = [] unless raw_cmds.is_a?(Array)
    cmds = raw_cmds.filter_map do |cmd|
      next nil unless cmd.is_a?(Hash)
      c2 = RPG::EventCommand.new
      if cmd["rmxp_raw"] == false
        XPX::CommandTranslator.translate(cmd, c2) rescue nil
      else
        c2.code       = ((cmd["code"]||0).to_i rescue 0)
        c2.indent     = ((cmd["indent"]||0).to_i rescue 0)
        plist = cmd["parameters"]
        c2.parameters = plist.is_a?(Array) ? plist.map{|x| x.nil? ? "" : x} : []
      end
      # Same coercion fixups as build_page — keeps imported data clean.
      if [101, 401, 355, 655, 108, 408].include?(c2.code)
        c2.parameters[0] = "" if c2.parameters.empty? || c2.parameters[0].nil?
        c2.parameters[0] = c2.parameters[0].to_s rescue ""
      end
      if c2.code == 209 && c2.parameters.size > 1 && c2.parameters[1].is_a?(Hash)
        c2.parameters[1] = XPX.build_move_route(c2.parameters[1])
      end rescue nil
      if [241, 245, 246, 247, 249, 250, 238, 132].include?(c2.code) && c2.parameters.size > 0
        c2.parameters[0] = XPX.build_audio_file(c2.parameters[0]) if c2.parameters[0].is_a?(Hash) || c2.parameters[0].is_a?(String)
      end rescue nil
      if c2.code == 223 && c2.parameters.size > 0 && c2.parameters[0].is_a?(Hash)
        c2.parameters[0] = XPX.build_tone(c2.parameters[0])
      end rescue nil
      if c2.code == 224 && c2.parameters.size > 0 && c2.parameters[0].is_a?(Hash)
        c2.parameters[0] = XPX.build_color(c2.parameters[0])
      end rescue nil
      c2
    end
    # RMXP convention: command list always ends with a code-0 terminator
    # (the "end of event" sentinel). Adding it unconditionally is fine —
    # the build_page path does the same.
    t = RPG::EventCommand.new; t.code = 0
    cmds << t unless cmds.last&.code == 0
    cmds
  end

  # Trigger string → integer mapping. RMXP's RPG::CommonEvent.@trigger:
  #   0 = None, 1 = Autorun, 2 = Parallel
  COMMON_EVENT_TRIGGER_MAP = {
    "None"     => 0,
    "Autorun"  => 1,
    "Parallel" => 2,
  }.freeze

  # Build Array<RPG::CommonEvent> from XPX_CommonEvents.json. Returns
  # nil if the sidecar is missing — caller falls back to rxdata.
  #
  # The format on disk is an array of dicts:
  #   [{"id":1, "name":"...", "trigger": 0|1|2|"None"|"Autorun"|"Parallel",
  #     "switch_id": 1, "list":[command-dict, ...]}, ...]
  #
  # Returns the same shape Marshal.load returns from CommonEvents.rxdata:
  # `[nil, RPG::CommonEvent, RPG::CommonEvent, ...]` — index 0 is nil
  # (RMXP's 1-based array convention). Plugins like Essentials' core
  # iterate `(1..$data_common_events.length-1).each` and assume nil at 0.
  def self.get_common_events
    data = _load_json_sidecar("XPX_CommonEvents.json")
    return nil unless data.is_a?(Array)
    out = [nil]
    data.each do |ce|
      next unless ce.is_a?(Hash)
      ev = RPG::CommonEvent.new
      ev.id   = (ce["id"]||out.length).to_i
      ev.name = (ce["name"]||"").to_s
      # Trigger may be int (already-coerced) or string ("Autorun" etc.)
      raw_trig = ce["trigger"]
      ev.trigger = if raw_trig.is_a?(Integer)
                     raw_trig
                   elsif raw_trig.is_a?(String)
                     COMMON_EVENT_TRIGGER_MAP[raw_trig] || 0
                   else
                     0
                   end
      ev.switch_id = (ce["switch_id"]||1).to_i
      ev.list = build_command_list(ce["list"])
      # Position by id so iteration order matches Essentials' expectations.
      while out.length <= ev.id
        out << nil
      end
      out[ev.id] = ev
    end
    out
  end

  # Apply XPX_System.json overrides to a loaded RPG::System instance.
  # Doesn't replace the whole object — just overwrites fields where
  # xpxdata is the canonical source. The rxdata-loaded sys keeps
  # supplying audio/UI defaults the editor doesn't yet model.
  #
  # Fields overridden:
  #   - start_map_id, start_x, start_y    (the orange "S" marker)
  #   - switches[]                         (Switches editor)
  #   - variables[]                        (Variables editor)
  #
  # Returns the modified sys. If sys is nil (rxdata missing), fabricates
  # a minimal RPG::System from the xpxdata.
  def self.apply_system_overlay(sys)
    data = _load_json_sidecar("XPX_System.json")
    return sys unless data.is_a?(Hash)
    if sys.nil?
      # No rxdata — fabricate a bare-bones RPG::System. Most fields stay
      # at their RMXP defaults; xpxdata fills in what it knows.
      begin
        sys = RPG::System.new
      rescue
        return nil   # RPG::System not even defined; nothing we can do
      end
    end
    # Start position. start_map_id 0 means "no start" in RMXP — refuse
    # to write 0 because Essentials' StartGame check raises on that.
    sm = (data["start_map_id"]||0).to_i
    if sm > 0
      sys.start_map_id = sm
      sys.start_x      = (data["start_x"]||0).to_i
      sys.start_y      = (data["start_y"]||0).to_i
    end
    # Switches / variables: array indexed 1..N, position 0 stays nil.
    # XPX stores them as [{"id": 1, "name": "..."}], we project to
    # array form. Skip slots with no name to avoid stomping rxdata
    # entries that the user hadn't explicitly redeclared in XPX.
    sw_src = data["switches"]
    if sw_src.is_a?(Array)
      sw_arr = (sys.switches || [nil]).dup
      sw_arr[0] = nil
      sw_src.each do |s|
        next unless s.is_a?(Hash)
        sid = (s["id"]||0).to_i
        next unless sid >= 1 && sid <= 5000
        nm = (s["name"]||"").to_s
        next if nm.empty?
        while sw_arr.length <= sid
          sw_arr << ""
        end
        sw_arr[sid] = nm
      end
      sys.switches = sw_arr
    end
    var_src = data["variables"]
    if var_src.is_a?(Array)
      var_arr = (sys.variables || [nil]).dup
      var_arr[0] = nil
      var_src.each do |v|
        next unless v.is_a?(Hash)
        vid = (v["id"]||0).to_i
        next unless vid >= 1 && vid <= 5000
        nm = (v["name"]||"").to_s
        next if nm.empty?
        while var_arr.length <= vid
          var_arr << ""
        end
        var_arr[vid] = nm
      end
      sys.variables = var_arr
    end
    sys
  rescue => e
    log "apply_system_overlay error: #{e.message}"
    sys
  end

  # Build the $data_mapinfos hash from XPX_MapInfos.json. Same shape
  # Marshal.load returns from MapInfos.rxdata: Hash[id => RPG::MapInfo].
  def self.get_map_infos
    data = _load_json_sidecar("XPX_MapInfos.json")
    return nil unless data.is_a?(Hash)
    out = {}
    data.each do |key, info|
      next unless info.is_a?(Hash)
      id = key.to_i
      next if id <= 0
      mi = RPG::MapInfo.new
      mi.name      = (info["name"]||"Map#{id}").to_s
      mi.parent_id = (info["parent_id"]||0).to_i
      mi.order     = (info["order"]||id).to_i
      mi.expanded  = !!info["expanded"]
      mi.scroll_x  = (info["scroll_x"]||0).to_i
      mi.scroll_y  = (info["scroll_y"]||0).to_i
      out[id] = mi
    end
    out.empty? ? nil : out
  end

  # ── Tilesets loader (Phase 5 of native xpxdata runtime) ──────────────────
  # Build a Tilesets array from XPX_Tilesets.xpxdata. Two operating modes:
  #
  #   OVERLAY (existing rxdata array): apply xpxdata fields on top of the
  #     rxdata-loaded tilesets. Used when both files exist — the editor
  #     normally writes both via tileset_export.py + mkxpz_exporter, so
  #     this is the common case. xpxdata wins for fields the editor
  #     models (passages, priorities, terrain_tags, autotile_names);
  #     rxdata supplies fields the editor doesn't model (panorama, fog,
  #     battleback).
  #
  #   FULL BUILD (rxdata missing): fabricate a fresh RPG::Tileset for each
  #     xpxdata entry. Fields the editor doesn't model get safe defaults.
  #     Used for pure-xpxdata projects that ship without Tilesets.rxdata.
  #
  # Returns the (possibly modified) tileset array, or nil if no xpxdata
  # is available — caller falls back to plain rxdata.
  def self._build_table_1d(arr)
    return nil unless arr.is_a?(Array) && !arr.empty?
    return nil unless defined?(::Table)
    t = ::Table.new(arr.size)
    arr.each_with_index do |v, i|
      next if v.nil?
      t[i] = v.to_i rescue 0
    end
    t
  end

  def self._apply_tileset_overlay(rpg_ts, xdata)
    # Apply XPX-canonical fields onto an existing RPG::Tileset. Mutates
    # rpg_ts in place. Skips fields that aren't in xdata so untouched
    # rxdata fields stay intact.
    return rpg_ts unless rpg_ts && xdata.is_a?(Hash)

    # ── DO NOT overwrite tileset_name / name from xpxdata ───────────
    # CRITICAL bug fix: previously this overlay rewrote
    # rpg_ts.tileset_name and rpg_ts.name with whatever xdata said.
    # That worked when XPX_Tilesets.xpxdata's `id` field matched the
    # rxdata array position 1:1 — every overlay applied the SAME
    # tileset's xpxdata to its own rxdata entry. But on projects where
    # RMXP's @id values drift from array positions (which happens when
    # tilesets are reordered or added/removed in the database), the
    # overlay applies the WRONG tileset's xpxdata to a position. Result:
    # the runtime's $data_tilesets[N] has the right passability data
    # but the WRONG tileset_name — Map's @tileset_id=N then loads a
    # different image than the editor showed (Mizzy hit this:
    # "biolab" expected but "emirates small rooms" loaded).
    #
    # tileset_name and name are FILE / IDENTITY fields. They don't
    # belong in the editor's edit surface — the user edits
    # passability, priority, and terrain tags. Leave the rxdata
    # values alone for those identity fields. Only replace what the
    # editor actually owns: passability, priorities, terrain_tags,
    # autotile_names (when explicitly set).
    if xdata["autotile_names"].is_a?(Array)
      # RMXP convention: autotile_names is a 7-slot array padded with
      # empty strings. Honor whatever the editor wrote (could be
      # shorter if some slots are unused) but pad up to 7.
      names = xdata["autotile_names"].map(&:to_s)
      while names.length < 7
        names << ""
      end
      rpg_ts.autotile_names = names[0, 7]
    end
    %w[passages priorities terrain_tags].each do |field|
      arr = xdata[field]
      next unless arr.is_a?(Array)
      tbl = _build_table_1d(arr)
      rpg_ts.send("#{field}=", tbl) if tbl
    end
    rpg_ts
  end

  def self._build_tileset_from_scratch(xdata)
    # Fabricate a fresh RPG::Tileset from xpxdata. Used when rxdata
    # is missing entirely (pure-xpxdata project). Defaults fill
    # rxdata-only fields so the runtime gets a valid object.
    return nil unless xdata.is_a?(Hash) && defined?(::RPG::Tileset)
    ts = ::RPG::Tileset.new
    ts.id           = (xdata["id"]||0).to_i
    _apply_tileset_overlay(ts, xdata)
    # Defaults for fields the editor doesn't model. Empty strings /
    # zeros are what RMXP puts on a fresh tileset, so this matches
    # how a brand-new RMXP-created tileset would look.
    ts.panorama_name   = ""
    ts.panorama_hue    = 0
    ts.fog_name        = ""
    ts.fog_hue         = 0
    ts.fog_opacity     = 64
    ts.fog_blend_type  = 0
    ts.fog_zoom        = 200
    ts.fog_sx          = 0
    ts.fog_sy          = 0
    ts.battleback_name = ""
    ts
  rescue => e
    log "_build_tileset_from_scratch error for tileset id=#{xdata['id']}: #{e.message}"
    nil
  end

  # Apply XPX_Tilesets.xpxdata to an rxdata-loaded tilesets array. Returns
  # the (possibly modified) array, or fabricates one if rxdata_array
  # is nil. Indexed by id (position 0 is nil per RMXP convention).
  def self.apply_tilesets_overlay(rxdata_array)
    data = _load_json_sidecar("XPX_Tilesets.xpxdata")
    return rxdata_array unless data.is_a?(Array)
    # Build TWO lookups so we can match by either id OR tileset_name.
    # Why both: the original @id-based match worked when RMXP's @id
    # values matched array positions 1:1, but on projects where ids
    # drifted (tilesets reordered/added/removed in the database) the
    # @id of an rxdata entry no longer points at the same logical
    # tileset as xpxdata's id. Matching by tileset_name (the image
    # filename) is robust to that drift — the file identity can't
    # drift, only the database index can.
    #
    # We try tileset_name first (most reliable), then fall back to
    # @id for entries that have no tileset_name.
    by_id   = {}
    by_name = {}
    data.each do |entry|
      next unless entry.is_a?(Hash)
      eid = (entry["id"]||0).to_i
      by_id[eid] = entry if eid > 0
      tn = entry["tileset_name"].to_s
      # Strip extension and lowercase so 'biolab.png' / 'BioLab' /
      # 'biolab' all collide on the same key.
      next if tn.empty?
      tn_norm = tn.sub(/\.\w+$/, "").downcase
      by_name[tn_norm] ||= entry
    end
    if rxdata_array.is_a?(Array) && !rxdata_array.empty?
      # Overlay mode: apply xpxdata to existing entries.
      # Match priority: tileset_name first (file identity), @id second.
      out = rxdata_array.map do |rt|
        next rt unless rt
        match_entry = nil
        rt_tn = (rt.tileset_name.to_s rescue "")
        unless rt_tn.empty?
          rt_tn_norm = rt_tn.sub(/\.\w+$/, "").downcase
          match_entry = by_name[rt_tn_norm]
        end
        if match_entry.nil?
          eid = (rt.id rescue nil)
          match_entry = by_id[eid] if eid
        end
        if match_entry
          _apply_tileset_overlay(rt, match_entry)
        else
          rt
        end
      end
      # Append any xpxdata tilesets that don't exist in rxdata
      # (id higher than the rxdata array's max AND tileset_name
      # not seen in rxdata). Rare but possible if a user adds
      # tilesets in XPX without re-running the rxdata writer.
      seen_names = {}
      out.compact.each do |t|
        tn = (t.tileset_name.to_s rescue "")
        next if tn.empty?
        seen_names[tn.sub(/\.\w+$/, "").downcase] = true
      end
      max_existing = out.compact.map do |t|
        (t.id rescue 0)
      end.max || 0
      by_id.each do |eid, entry|
        next if eid <= max_existing
        # Skip if this entry's tileset_name is already in the array
        # (we'd duplicate it).
        en_tn = entry["tileset_name"].to_s
        unless en_tn.empty?
          en_tn_norm = en_tn.sub(/\.\w+$/, "").downcase
          next if seen_names[en_tn_norm]
        end
        new_ts = _build_tileset_from_scratch(entry)
        next unless new_ts
        # Pad with nils so out[eid] = new_ts at the right index.
        while out.length <= eid
          out << nil
        end
        out[eid] = new_ts
      end
      return out
    end
    # Full build mode: rxdata array missing or empty. Fabricate from
    # scratch. Index 0 stays nil per RMXP convention.
    out = [nil]
    by_id.keys.sort.each do |eid|
      new_ts = _build_tileset_from_scratch(by_id[eid])
      next unless new_ts
      while out.length <= eid
        out << nil
      end
      out[eid] = new_ts
    end
    out.length > 1 ? out : nil
  rescue => e
    log "apply_tilesets_overlay error: #{e.message}"
    rxdata_array
  end

  def self.build_move_route(mr_data)
    return RPG::MoveRoute.new unless mr_data.is_a?(Hash)
    mr = RPG::MoveRoute.new
    mr.repeat    = mr_data["repeat"] != false
    mr.skippable = !!mr_data["skippable"]
    mc_list = (mr_data["list"]||[]).is_a?(Array) ? mr_data["list"] : []
    mc_cmds = mc_list.filter_map do |mc|
      next nil unless mc.is_a?(Hash)
      m2 = RPG::MoveCommand.new
      m2.code = ((mc["code"]||0).to_i rescue 0)
      m2.parameters = (mc["parameters"]||[]).is_a?(Array) ? mc["parameters"] : []
      m2
    end
    t2 = RPG::MoveCommand.new; t2.code = 0
    mc_cmds << t2 unless mc_cmds.last&.code == 0
    mr.list = mc_cmds
    mr
  end

  def self.build_audio_file(data)
    return data if data.is_a?(RPG::AudioFile)
    return RPG::AudioFile.new(data.to_s, 100, 100) if data.is_a?(String)
    return RPG::AudioFile.new("", 100, 100) unless data.is_a?(Hash)
    RPG::AudioFile.new(
      (data["name"]||data["file"]||"").to_s,
      (data["volume"]||100).to_i,
      (data["pitch"]||100).to_i
    )
  end

  def self.build_tone(data)
    return data if defined?(Tone) && data.is_a?(Tone)
    return Tone.new(0,0,0,0) unless data.is_a?(Hash)
    r  = (data["red"]  || data["r"] || 0).to_f
    g  = (data["green"]|| data["g"] || 0).to_f
    b  = (data["blue"] || data["b"] || 0).to_f
    gr = (data["gray"] || data["grey"] || data["a"] || 0).to_f
    Tone.new(r, g, b, gr)
  rescue
    Tone.new(0,0,0,0)
  end

  def self.build_color(data)
    return data if defined?(Color) && data.is_a?(Color)
    return Color.new(0,0,0,0) unless data.is_a?(Hash)
    r = (data["red"]  || data["r"] || 0).to_f
    g = (data["green"]|| data["g"] || 0).to_f
    b = (data["blue"] || data["b"] || 0).to_f
    a = (data["alpha"]|| data["a"] || 255).to_f
    Color.new(r, g, b, a)
  rescue
    Color.new(0,0,0,0)
  end

  def self.build_map_info(d)
    i = RPG::MapInfo.new
    i.name = (d["name"]||"Map").to_s; i.parent_id = 0; i.order = (d["map_id"]||0).to_i
    i
  end

  # ── Translator: XPX-native cmd_type → RMXP code+parameters ────────────────
  #
  # When a user authors an event in XPX's event editor, commands serialize
  # as {cmd_type: "Show Message", params: {text: "Hi"}} rather than the
  # raw RMXP {code: 101, parameters: ["Hi"]} format.
  #
  # RPG::Interpreter only knows how to read raw RMXP shape, so before
  # handing commands to the interpreter we translate native ones back to
  # raw form. This module is the inverse of save_manager._rmxp_params_to_dict
  # in the editor.
  #
  # The cmd_type names match COMMAND_TYPES from event_editor.py.
  #
  # New cmd_types added in the editor MUST be added here too — otherwise
  # they'll be silently translated to code 0 (end-of-list terminator) and
  # the interpreter will skip them.
  module CommandTranslator
    # Direction string → RMXP integer for Transfer Player
    DIRS = {"Retain"=>0, "Down"=>2, "Left"=>4, "Right"=>6, "Up"=>8}

    # Audio command names → RMXP RPG::EventCommand code. The
    # canonical RMXP table:
    #   241 Play BGM  / 242 Fade BGM
    #   243 Play BGS  / 244 Fade BGS
    #   245 Memorize BGM/BGS  / 246 Restore BGM/BGS
    #   247 Play ME   / 248 Play SE   / 249 Stop SE
    # Earlier revisions of this map had several wrong codes
    # (Play BGS=>245 hit Memorize, Play SE=>250 hit Battle
    # Processing, etc.), so the audio commands authored from
    # XPX silently misfired at runtime. Fixed now — this table
    # mirrors RMXP's verbatim. Stop BGM/BGS map to the Fade
    # variants with frames=0 since RMXP has no instant-stop
    # opcode for those.
    AUDIO_PLAY = {"Play BGM"=>241, "Play BGS"=>243, "Play ME"=>247,
                   "Play Sound Effect"=>248}
    AUDIO_STOP = {"Stop BGM"=>242, "Stop BGS"=>244, "Stop SE"=>249}

    def self.translate(cmd, evcmd)
      ctype  = (cmd["cmd_type"] || "Script").to_s
      params = cmd["params"] || {}
      indent = (cmd["indent"]||0).to_i rescue 0
      evcmd.indent = indent

      code, plist = encode(ctype, params)
      evcmd.code       = code
      evcmd.parameters = plist
    rescue => err
      # Translation failures shouldn't crash boot — fall back to a Script
      # comment so the interpreter sees something visible in the log
      xpx_puts "CommandTranslator error for #{ctype rescue '?'}: #{err.message}"
      evcmd.code = 108
      evcmd.indent = indent rescue 0
      evcmd.parameters = ["XPX-untranslated: #{ctype rescue '?'}"]
    end

    def self.encode(ctype, p)
      case ctype
      when "Show Message"
        # 101 = first line of message; further lines would be 401 but
        # the editor stores everything as a single multi-line string,
        # which RGSS handles by splitting on \n during display.
        [101, [(p["text"]||"").to_s]]

      when "Show Choices"
        # 102 — parameters: [choices_array, cancel_type]
        choices = (p["choices"]||[]).map(&:to_s)
        cancel  = (p["cancel_type"]||5).to_i
        [102, [choices, cancel]]

      when "When Choice"
        # 402 — branch begin: [choice_index, choice_text]
        [402, [(p["choice_index"]||0).to_i, (p["choice_text"]||"").to_s]]

      when "When Cancel"
        # 403 — cancel branch: empty params
        [403, []]

      when "Choice End"
        # 404 — end of show-choices block
        [404, []]

      when "Change Switch"
        # 121 — [start_id, end_id, value(0=ON,1=OFF)]
        sw = (p["switch_id"]||1).to_i
        v  = ((p["value"]||"ON").to_s.upcase == "OFF") ? 1 : 0
        [121, [sw, sw, v]]

      when "Change Variable"
        # 122 — [start_id, end_id, op_type, source_type, value]
        # op_type: 0=Set 1=Add 2=Sub 3=Mul 4=Div 5=Mod
        # source_type: 0=constant
        var_id = (p["var_id"]||1).to_i
        op_map = {"="=>0, "+="=>1, "-="=>2, "*="=>3, "/="=>4, "%="=>5}
        op     = op_map[(p["operation"]||"=").to_s] || 0
        val    = (p["value"]||0).to_i rescue 0
        [122, [var_id, var_id, op, 0, val]]

      when "Change Self Switch"
        # 123 — [character, value(0=ON,1=OFF)]
        ch = (p["ch"]||"A").to_s
        v  = ((p["value"]||"ON").to_s.upcase == "OFF") ? 1 : 0
        [123, [ch, v]]

      when "Conditional Branch"
        # 111 — [subtype, ...subtype-specific]
        # 0=Switch 1=Variable 2=Self Switch 12=Script
        sub = (p["condition"]||"Switch").to_s
        state_str = (p["state"]||"ON / True").to_s.upcase
        on_off = state_str.include?("OFF") || state_str.include?("FALSE") ? 1 : 0
        case sub
        when "Switch"
          # [0, switch_id, value(0=ON,1=OFF)]
          [111, [0, (p["id"]||1).to_i, on_off]]
        when "Variable"
          # [1, var_id, source_type=0, source_value, op_type]
          # We use op=0 (==) and source=constant 0 — editor's UI is
          # currently boolean-only. If you add full variable comparison
          # later, extend this.
          [111, [1, (p["id"]||1).to_i, 0, 0, 0]]
        when "Self Switch"
          # [2, ch, value(0=ON,1=OFF)]
          [111, [2, (p["self_switch_ch"]||"A").to_s, on_off]]
        when "Script"
          # [12, script_string]
          [111, [12, (p["script"]||"").to_s]]
        else
          [111, [0, 1, 0]]
        end

      when "Else"
        # 411 — else branch of conditional
        [411, []]

      when "Branch End", "Conditional Branch End"
        # 412 — end of conditional block
        [412, []]

      when "Loop"
        # 112 — start loop
        [112, []]

      when "Repeat Above", "Loop End"
        # 413 — closes a loop
        [413, []]

      when "Break Loop"
        [113, []]

      when "Exit Event Processing"
        [115, []]

      when "Wait"
        # 106 — [frames]
        [106, [(p["frames"]||60).to_i]]

      when "Transfer Player"
        # 201 — [appoint_type, map_id, x, y, direction, fading]
        # appoint_type: 0 = Direct, 1 = Variable Designation
        dir_in = p["direction"]
        d = if dir_in.is_a?(Integer)
              dir_in
            else
              DIRS[(dir_in||"Retain").to_s] || 0
            end
        [201, [0, (p["map_id"]||1).to_i, (p["x"]||0).to_i,
               (p["y"]||0).to_i, d, 0]]

      when "Set Move Route"
        # 209 — [character, RPG::MoveRoute]
        # character: -1=Player, 0=This event, N=Event ID
        target = p["target"]
        ch = case target
             when "Player" then -1
             when "This event", "Self" then 0
             else
               # Numeric or "Event #N" string
               (target.to_s.match(/(\d+)/)[1].to_i rescue 0)
             end
        # If the editor stored a full MoveRoute we'd build it here, but
        # the current editor stores Move Route Step commands separately
        # (each Move Route Step adds a 509 command after the 209). To
        # keep behavior consistent with how RGSS::Interpreter walks the
        # 509s, emit an empty MoveRoute here.
        mr = RPG::MoveRoute.new
        terminator = RPG::MoveCommand.new
        terminator.code = 0
        mr.list = [terminator]
        [209, [ch, mr]]

      when "Move Route Step"
        # 509 — [RPG::MoveCommand]
        mc = RPG::MoveCommand.new
        mc.code = (p["move_code"]||0).to_i
        raw = p["raw"]
        if raw.is_a?(Hash)
          plist = raw["parameters"] || raw["@parameters"] || []
          mc.parameters = plist.is_a?(Array) ? plist : []
        else
          mc.parameters = []
        end
        [509, [mc]]

      when *AUDIO_PLAY.keys
        code = AUDIO_PLAY[ctype]
        af   = RPG::AudioFile.new(
          (p["file"]||"").to_s,
          (p["volume"]||100).to_i,
          (p["pitch"]||100).to_i,
        )
        [code, [af]]

      when *AUDIO_STOP.keys
        [AUDIO_STOP[ctype], []]

      when "Script"
        # 355 — [code]; multi-line scripts get extra 655 continuations
        # but the editor stores the whole script as a single string.
        # mkxp-z's interpreter accepts the whole thing on a single 355.
        code_text = (p["code"] || p["text"] || "").to_s
        [355, [code_text]]

      when "Comment"
        [108, [(p["text"]||"").to_s]]

      when "Screen Color Tone"
        # 223 — [Tone, frames]
        r  = (p["red"]   || p["r"] || 0).to_f
        g  = (p["green"] || p["g"] || 0).to_f
        b  = (p["blue"]  || p["b"] || 0).to_f
        gr = (p["grey"]  || p["gray"] || p["a"] || 0).to_f
        fr = (p["frames"]||20).to_i
        [223, [Tone.new(r,g,b,gr), fr]]

      when "Screen Flash"
        # 224 — [Color, frames]
        r = (p["red"]||255).to_f
        g = (p["green"]||255).to_f
        b = (p["blue"]||255).to_f
        s = (p["strength"]||128).to_f
        fr = (p["frames"]||8).to_i
        [224, [Color.new(r,g,b,s), fr]]

      when "Screen Shake"
        # 225 — [power, speed, frames]
        [225, [(p["power"]||5).to_i, (p["speed"]||5).to_i,
               (p["frames"]||20).to_i]]

      # ── Newly-added commands ────────────────────────────────────────
      when "Call Common Event"
        # 117 — [common_event_id]
        [117, [(p["common_event_id"]||1).to_i]]

      when "Erase Event"
        # 116 — no params; despawns the current event for the rest of
        # the map session (cleared on map re-entry).
        [116, []]

      when "Wait for Move's Completion"
        # 210 — no params; pauses the interpreter until every active
        # Set Move Route on the map has finished.
        [210, []]

      when "Label"
        # 118 — [name]
        [118, [(p["name"]||"").to_s]]

      when "Jump to Label"
        # 119 — [name]; RMXP scans the page for a matching 118 and
        # rewinds/advances the interpreter to that index.
        [119, [(p["name"]||"").to_s]]

      when "Show Animation"
        # 207 — [character, animation_id]
        # character: -1=Player, 0=This event, N=Event #N
        ch_str = (p["character"]||"This event").to_s
        ch = case ch_str
             when "Player"     then -1
             when "This event" then 0
             else (ch_str.match(/(\d+)/)[1].to_i rescue 0)
             end
        [207, [ch, (p["animation_id"]||1).to_i]]

      when "Set Event Location"
        # 202 — [character, appoint_type, x, y, direction]
        # appoint_type 0=Direct (we only author Direct from the dialog).
        ch_str = (p["character"]||"This event").to_s
        ch = case ch_str
             when "Player"     then -1
             when "This event" then 0
             else (ch_str.match(/(\d+)/)[1].to_i rescue 0)
             end
        d = DIRS[(p["direction"]||"Retain").to_s] || 0
        [202, [ch, 0, (p["x"]||0).to_i, (p["y"]||0).to_i, d]]

      when "Scroll Map"
        # 203 — [direction, distance, speed]
        d = DIRS[(p["direction"]||"Down").to_s] || 2
        [203, [d, (p["distance"]||1).to_i, (p["speed"]||4).to_i]]

      when "Picture"
        # 231/232/235 — action picker drives which RMXP code lands.
        # The decoder preserves the extra RMXP fields (origin, x_type,
        # y_type, zoom_x, zoom_y, opacity, blend_type) under prefixed
        # keys (_origin, _zoom_x, etc.), so imported pictures with
        # custom zoom/opacity/blend round-trip with full fidelity. New
        # authoring uses the defaults baked in below.
        action = (p["action"]||"Show").to_s
        num = (p["number"]||1).to_i
        case action
        when "Show"
          [231, [num, (p["file"]||"").to_s,
                 (p["_origin"]||0).to_i,
                 (p["_x_type"]||0).to_i, (p["x"]||0).to_i,
                 (p["_y_type"]||0).to_i, (p["y"]||0).to_i,
                 (p["_zoom_x"]||100).to_i, (p["_zoom_y"]||100).to_i,
                 (p["_opacity"]||255).to_i, (p["_blend_type"]||0).to_i]]
        when "Move"
          [232, [num,
                 (p["_dup"]||0).to_i,
                 (p["_x_type"]||0).to_i, (p["x"]||0).to_i,
                 (p["_y_type"]||0).to_i, (p["y"]||0).to_i,
                 (p["_zoom_x"]||100).to_i, (p["_zoom_y"]||100).to_i,
                 (p["_opacity"]||255).to_i, (p["_blend_type"]||0).to_i,
                 (p["frames"]||60).to_i]]
        else
          # Erase or unknown action
          [235, [num]]
        end

      when "Weather Effects"
        # 236 — [type, power, frames]
        type_map = {"None"=>0, "Rain"=>1, "Storm"=>2, "Snow"=>3}
        t = type_map[(p["type"]||"None").to_s] || 0
        [236, [t, (p["power"]||0).to_i, (p["frames"]||20).to_i]]

      when "Change Gold"
        # 125 — [op_type(0=add,1=sub), src_type(0=const,1=var), value]
        op = (p["operation"]||"+").to_s == "+" ? 0 : 1
        [125, [op, (p["src_type"]||0).to_i, (p["value"]||0).to_i]]

      when "Change Inventory"
        # 126 / 127 / 128 — code picked by `kind`. Layout shared:
        # [item_id, op_type, src_type, value].
        kind = (p["kind"]||"Item").to_s
        code = case kind
               when "Weapon" then 127
               when "Armor"  then 128
               else 126
               end
        op = (p["operation"]||"+").to_s == "+" ? 0 : 1
        [code, [(p["item_id"]||1).to_i, op,
                (p["src_type"]||0).to_i, (p["value"]||1).to_i]]

      when "Memorize / Restore BGM"
        # 245 Memorize / 246 Restore — both no-param.
        mode = (p["mode"]||"Memorize").to_s
        code = (mode == "Restore") ? 246 : 245
        [code, []]

      when "Transition"
        # 221 Prepare / 222 Execute — paired pseudo-commands. Mode
        # picks the code; Execute optionally carries a file from
        # Graphics/Transitions/ for the fade.
        mode = (p["mode"]||"Prepare").to_s
        if mode == "Execute"
          [222, [(p["file"]||"").to_s]]
        else
          [221, []]
        end

      when "Input Number"
        # 103 — [var_id, digit_count]
        [103, [(p["var_id"]||1).to_i, (p["digits"]||4).to_i]]

      when "Name Input"
        # 252 — [actor_id, max_chars]
        [252, [(p["actor_id"]||1).to_i, (p["max_chars"]||6).to_i]]

      when "Control Timer"
        # 124 — [mode_int, seconds] (RMXP convention: 0=Start, 1=Stop).
        mode_int = ((p["mode"]||"Start").to_s == "Stop") ? 1 : 0
        [124, [mode_int, (p["seconds"]||60).to_i]]

      else
        # Unknown cmd_type — emit a comment so it shows in the log but
        # doesn't crash the interpreter
        [108, ["[XPX] Unknown cmd_type: #{ctype}"]]
      end
    end
  end

  # ── Patch fix_event_use to guard nil page lists ───────────────────────────
  def self.patch_compiler_safety
    # Patch RPG::Event::Page#list to never return nil.
    # Uses attr_accessor fallback if alias_method fails.
    begin
      RPG::Event::Page.class_eval do
        # Store original via instance variable to avoid alias issues
        define_method(:list) do
          @list = [RPG::EventCommand.new.tap {|c2| c2.code=0; c2.indent=0; c2.parameters=[]}] unless @list.is_a?(Array) && !@list.empty?
          unless @list.last.is_a?(RPG::EventCommand) && @list.last.code == 0
            t2 = RPG::EventCommand.new; t2.code=0; t2.indent=0; t2.parameters=[]
            @list << t2
          end
          @list.each {|cmd| cmd.parameters ||= [] if cmd.is_a?(RPG::EventCommand)}
          @list
        end
        define_method(:list=) do |val|
          @list = val.is_a?(Array) ? val : []
        end
      end
      xpx_puts "RPG::Event::Page#list patched for nil-safety"
    rescue => e
      xpx_puts "Page safety patch skipped: #{e.message}"
    end
  end

  # ── Patch load_data AND $data_maps ───────────────────────────────────────
  def self.patch_load_data
    # Intercept load_data so map loads PREFER xpxdata (XPX-native JSON)
    # over rxdata (RMXP marshalled binary). The rxdata path remains a
    # fallback for projects that haven't been XPX-saved or for files
    # XPX hasn't indexed.
    #
    # Note: this MUST be done with alias_method so existing call-sites
    # keep working — Essentials' compile_trainer_events and many other
    # places call load_data(...) directly.
    Kernel.module_eval do
      alias :_xpx_orig_load_data :load_data rescue nil
      define_method(:load_data) do |fn|
        if fn.is_a?(String)
          # Map###.rxdata → check for indexed xpxdata equivalent first.
          if fn =~ /Map(\d+)\.rxdata$/i
            map_id = $1.to_i
            xpx_map = XPX.get_map(map_id)
            return xpx_map if xpx_map
            # No xpxdata for this map — fall through to rxdata fallback
          end

          # ── Native xpxdata routing (Phase 1) ────────────────────────
          # CommonEvents: full replacement when XPX_CommonEvents.json
          # exists. Falls back to rxdata when missing.
          if fn =~ /CommonEvents\.rxdata$/i
            ce = XPX.get_common_events rescue nil
            return ce if ce
            # else fall through
          end

          # System: load rxdata (if present), then apply xpxdata overlay
          # for canonical fields (start position, switches, variables).
          # Result is rxdata-like for unknown fields, xpxdata-canonical
          # for fields the editor actually owns.
          if fn =~ /System\.rxdata$/i
            sys = nil
            begin
              sys = _xpx_orig_load_data(fn)
            rescue
              sys = nil
            end
            sys = XPX.apply_system_overlay(sys) rescue sys
            return sys if sys
            # else fall through to rxdata error path below
          end

          # MapInfos: full replacement when XPX_MapInfos.json exists.
          # Falls back to rxdata when missing.
          if fn =~ /MapInfos\.rxdata$/i
            mi = XPX.get_map_infos rescue nil
            return mi if mi
            # else fall through
          end

          # Tilesets: load rxdata first (for fields the editor doesn't
          # model — panorama, fog, battleback), then overlay xpxdata on
          # top so the editor's passability/priority/terrain edits win.
          # If rxdata is missing entirely, fabricate from xpxdata so
          # pure-xpxdata projects boot without Tilesets.rxdata.
          if fn =~ /Tilesets\.rxdata$/i
            tilesets_arr = nil
            begin
              tilesets_arr = _xpx_orig_load_data(fn)
            rescue
              tilesets_arr = nil
            end
            tilesets_arr = XPX.apply_tilesets_overlay(tilesets_arr) rescue tilesets_arr
            return tilesets_arr if tilesets_arr
            # else fall through to rxdata error path
          end
        end
        # Default path: use the original load_data, with empty-map
        # safety net for missing map files (prevents Essentials boot
        # crashes when a referenced map has no rxdata).
        begin
          _xpx_orig_load_data(fn)
        rescue => _e
          if fn.is_a?(String) && fn =~ /Map(\d+)\.rxdata$/i
            XPX.empty_map
          else
            xpx_puts "load_data failed for #{fn}: #{_e.message}"
            nil
          end
        end
      end
    end

    # Populate $data_mapinfos for the map tree
    $data_mapinfos ||= {}
    ($xpx_map_infos||{}).each {|id, info| $data_mapinfos[id] ||= info}

    # Populate $data_maps eagerly — Essentials v21 compile_trainer_events
    # reads $data_maps[id].events directly without going through load_data.
    # We must fill it now so all map event pages are non-nil.
    $data_maps ||= {}
    ($xpx_map_index||{}).each_key do |id|
      next if $data_maps[id]   # already loaded
      map = XPX.get_map(id)
      $data_maps[id] = map if map
    end
  end

  # ── Wrap $data_maps with a default-proc so missing ids return a real map ──
  # The proc is the lazy-rebuild path used after Game_Map#setup evicts a
  # stale cached map (bridge fix #1). When a plugin or core script reads
  # $data_maps[id] for an evicted ID, the proc:
  #
  #   1. Tries XPX.get_map(id) — rebuilds from .xpxdata, returns a fresh
  #      RPG::Map. This is the common case after eviction.
  #   2. Falls back to an empty map if get_map fails (e.g. id has no
  #      backing .xpxdata file). Keeps .events / .data accessors safe
  #      so the caller doesn't NoMethodError on nil.
  #
  # Original implementation only had the empty-map fallback. After
  # adding eviction in the setup wrapper, that would have caused
  # plugins reading $data_maps[id] post-eviction to see EMPTY maps
  # until the next load_data round-tripped — broken state. The
  # get_map call here closes that gap.
  def self.install_data_maps_guard
    return unless $data_maps.is_a?(Hash) && !$data_maps.default_proc
    $data_maps.default_proc = proc do |h, id|
      m = XPX.get_map(id) rescue nil
      if m
        h[id] = m
      else
        empty = RPG::Map.new(20, 15)
        empty.events = {}
        h[id] = empty
      end
    end
  end

  # ── Patch pbRgssExists? to recognise XPX-virtualised map files ──────────
  # Essentials' 001_StartGame.rb uses pbRgssExists?("Data/Map###.rxdata")
  # to verify the start map is on disk before launching, raising "No
  # starting position was set in the map editor" if the check fails.
  # After XPX conversion the original .rxdata files are renamed to
  # .rxdata.bak, so the on-disk existence check fails even though our
  # patched load_data would happily serve the map from xpxdata.
  #
  # The fix: prepend a module to Kernel that intercepts pbRgssExists?
  # for Map###.rxdata paths and returns true when the ID is in
  # $xpx_map_index. Defers to the original for everything else
  # (Common Events, Tilesets, anything else) via `super`. We use
  # prepend rather than alias_method because pbRgssExists? isn't
  # defined yet when this preload runs — Essentials scripts haven't
  # loaded. Prepend installs the wrapper into the method-lookup
  # chain BEFORE Essentials defines the original; when the original
  # is later defined, our wrapper is already in place and super
  # routes to it cleanly.
  def self.patch_pbrgssexists
    return if defined?(XPX_RgssExistsPatch)
    Object.const_set(:XPX_RgssExistsPatch, Module.new do
      def pbRgssExists?(fn)
        if fn.is_a?(String) && fn =~ /Map(\d+)\.rxdata$/i
          mid = $1.to_i
          idx = ($xpx_map_index || {})
          return true if idx.key?(mid)
        end
        # Fall through to the Essentials-defined original. If for some
        # reason the original isn't loaded yet (super raises NoMethodError),
        # fall back to a plain File.exist? on the GAME_ROOT-relative path.
        begin
          super
        rescue NoMethodError
          full = File.join(GAME_ROOT, fn.to_s)
          File.exist?(full)
        end
      end
    end)
    Kernel.prepend(XPX_RgssExistsPatch)
  end

  # ── Autotile database load ─────────────────────────────────────────────
  # Parse the autotile DB sidecar into $xpx_autotile_db. The DB is
  # filename-keyed; each entry holds is_water_type / animation_speed /
  # frame_count / frame_layout / terrain_tag_id / priority / passability
  # for one autotile image. Defensive throughout: a missing or malformed
  # file leaves $xpx_autotile_db as an empty Hash, and downstream code
  # falls back to v21 stock behavior in that case.
  #
  # File priority: prefer .xpxdata (the canonical export name) over
  # .json (legacy name). The exporter switched to .xpxdata for all
  # sidecars; reading the stale .json kept the runtime on outdated
  # is_water_type / terrain_tag_id values long after the editor
  # rewrote them — for example, flipping Water rock to "force-ground"
  # in the editor never reached the runtime because the .xpxdata
  # update was ignored in favour of the older .json.
  def self.load_autotile_database
    $xpx_autotile_db ||= {}
    base = File.join(GAME_ROOT, "Data", "XPX_AutotileDatabase")
    path = nil
    if File.exist?(base + ".xpxdata")
      path = base + ".xpxdata"
    elsif File.exist?(base + ".json")
      path = base + ".json"
    end
    if path.nil?
      log "Autotile DB: not found (.xpxdata or .json), using stock v21 defaults"
      return
    end
    unless defined?(JSON)
      log "Autotile DB: JSON stdlib unavailable — DB load skipped"
      return
    end
    begin
      raw = File.read(path, encoding: "UTF-8")
      parsed = JSON.parse(raw)
      if parsed.is_a?(Hash)
        $xpx_autotile_db = parsed
        log "Autotile DB: #{$xpx_autotile_db.size} entries loaded from #{File.basename(path)}"
      else
        log "Autotile DB: root is not a Hash (got #{parsed.class})"
      end
    rescue => e
      log "Autotile DB load failed: #{e.class}: #{e.message}"
    end
  end

  # ── Autotile kind classifier ───────────────────────────────────────────
  # Mirror of mkxpz_exporter._classify_autotile_layout. The editor uses
  # this exact decision tree to write extra_autotiles.large/.single in
  # XPX_Tilesets.xpxdata; the runtime must agree or v21's EXTRA_AUTOTILES
  # layout drifts from the tile_id encoding produced by build_map and
  # autotiles render at the wrong position (or flash, when their cached
  # bitmap is mis-sized for the slot).
  #
  # Decision order:
  #   1. DB entry's frame_layout, when explicitly set
  #   2. Image height (32px → single, anything else → large)
  #   3. Default → large
  #
  # Cached per-filename in $xpx_autotile_kind_cache because step 2
  # opens a Bitmap each call. With 171 maps × ~14 slots, no cache means
  # ~2400 Bitmap loads at boot.
  def self.classify_autotile_kind(fname)
    $xpx_autotile_kind_cache ||= {}
    cached = $xpx_autotile_kind_cache[fname]
    return cached if cached
    db    = ($xpx_autotile_db||{})[fname] || {}
    layout = (db["frame_layout"]||"").to_s
    if layout == "single_row_32px"
      $xpx_autotile_kind_cache[fname] = "single"
      return "single"
    elsif layout == "horizontal_96px"
      $xpx_autotile_kind_cache[fname] = "large"
      return "large"
    end
    # Image-height fallback. pbGetAutotile loads from
    # Graphics/Autotiles/<fname>.png (or animated variants).
    # pbGetAutotile is defined in Essentials's AnimatedBitmap.rb,
    # which loads AFTER XPX_Preload.rb. Boot-time callers (e.g. the
    # start-map audit) that hit this before Essentials's scripts run
    # don't have pbGetAutotile available — we skip the cache write
    # in that case so the next call (post-Essentials) gets a real
    # classification instead of a poisoned "large" default.
    if !defined?(pbGetAutotile)
      return "large"  # Best-effort default; do NOT cache.
    end
    kind = "large"
    begin
      bmp = pbGetAutotile(fname) rescue nil
      if bmp && !bmp.disposed? && bmp.height == 32
        kind = "single"
      end
      bmp.dispose if bmp && !bmp.disposed?
    rescue
      # Stay on "large" default.
    end
    $xpx_autotile_kind_cache[fname] = kind
    kind
  end

  # ── EXTRA_AUTOTILES resolver ───────────────────────────────────────────
  # v21 defines EXTRA_AUTOTILES as a CLASS constant inside
  # `class TilemapRenderer` (001_TilemapRenderer.rb line 40), so the
  # full name is TilemapRenderer::EXTRA_AUTOTILES. Looking it up via
  # Object.const_get(:EXTRA_AUTOTILES) raises NameError because it's
  # not at top level. Some forks/plugins hoist the constant to top
  # level — try the canonical class scope first, then fall back.
  # Returns nil if the constant isn't defined anywhere yet (which is
  # the case during XPX boot, before Scripts.rxdata loads).
  def self.resolve_extra_autotiles
    if defined?(TilemapRenderer)
      val = TilemapRenderer.const_get(:EXTRA_AUTOTILES) rescue nil
      return val if val
    end
    Object.const_get(:EXTRA_AUTOTILES) rescue nil
  end

  # ── EXTRA_AUTOTILES populate ───────────────────────────────────────────
  # Read XPX_Tilesets.json and populate EXTRA_AUTOTILES with the
  # per-tileset {large, single} filename lists. v21 expects positional
  # array-of-arrays: EXTRA_AUTOTILES[tileset_id] = [[large_names], [single_names]]
  # so we translate from our editor-friendly hash form here.
  #
  # This MUST run after the script that defines EXTRA_AUTOTILES
  # (typically 001_TilemapRenderer.rb in v21) — we hook a TracePoint to
  # detect when that constant is first assigned, and populate immediately.
  def self.populate_extra_autotiles
    # Phase 3: prefer .xpxdata, fall back to .json for projects that
    # haven't been re-saved since the rename. _load_json_sidecar
    # handles the priority + parsing so we don't duplicate the lookup
    # logic here.
    parsed = _load_json_sidecar("XPX_Tilesets.xpxdata") rescue nil
    if parsed.nil?
      log "Tilesets sidecar: not found (XPX_Tilesets.xpxdata or .json), EXTRA_AUTOTILES not populated"
      return
    end
    # Resolve EXTRA_AUTOTILES. v21 defines it as a CLASS constant
    # inside `class TilemapRenderer`, so it's TilemapRenderer::EXTRA_AUTOTILES,
    # NOT a top-level constant. Object.const_get(:EXTRA_AUTOTILES)
    # raises NameError. We try the TilemapRenderer scope first (the
    # canonical v21 location) and fall back to top-level for projects
    # that have hoisted the constant.
    target = XPX.resolve_extra_autotiles
    if target.nil?
      log "Tilesets sidecar: EXTRA_AUTOTILES not defined yet — skipping"
      return
    end
    unless target.is_a?(Hash)
      log "Tilesets sidecar: EXTRA_AUTOTILES is not a Hash (got #{target.class})"
      return
    end
    begin
      tilesets = parsed.is_a?(Array) ? parsed : []
      # $xpx_extra_slot_translation maps each tileset_id to a hash of
      # editor_slot → [kind, position-within-kind]. build_map (down in
      # this same module) uses it to encode tile_ids in v21's expected
      # layout for extended autotiles. Without this table, build_map
      # would fall back to the legacy "48 + slot*48" formula which
      # gives v21's renderer the wrong autotile bitmap whenever the
      # editor's slot order doesn't match large-then-single layout.
      $xpx_extra_slot_translation ||= {}
      $xpx_extra_slot_meta        ||= {}  # tid => {large_count: N}
      added = 0
      tilesets.each do |ts|
        next unless ts.is_a?(Hash)
        tid = ts["id"]
        next unless tid.is_a?(Integer) && tid > 0
        extras = ts["extra_autotiles"]
        next unless extras.is_a?(Hash)
        large  = extras["large"]  || []
        single = extras["single"] || []
        slots  = extras["slots"]  || []  # round 14+ wire format
        next if large.empty? && single.empty?
        # v21's EXTRA_AUTOTILES is positional: [[large_names], [single_names]]
        # — both sublists required, either can be empty.
        target[tid] = [Array(large), Array(single)]

        # Build the translation table from `slots` if present (round 14+
        # exporter). Each slot entry has slot/name/kind keys. We compute
        # the position within its kind by counting earlier slots of the
        # same kind. Empty slots (no name) are tracked but won't be
        # paintable.
        if slots.is_a?(Array) && !slots.empty?
          slot_table = {}
          large_idx  = 0
          single_idx = 0
          slots.each do |entry|
            next unless entry.is_a?(Hash)
            slot_num = entry["slot"]
            kind     = entry["kind"]
            name     = entry["name"]
            next unless slot_num.is_a?(Integer)
            if name && !name.empty?
              if kind == "single"
                slot_table[slot_num] = ["single", single_idx]
                single_idx += 1
              else
                # default to large (matches editor's classifier fallback)
                slot_table[slot_num] = ["large", large_idx]
                large_idx += 1
              end
            end
          end
          $xpx_extra_slot_translation[tid] = slot_table
          $xpx_extra_slot_meta[tid] = { "large_count" => large.length }
        end

        added += 1
      end
      log "EXTRA_AUTOTILES populated for #{added} tileset(s)"
      log "Extra slot translation table built for #{$xpx_extra_slot_translation.size} tileset(s)"
    rescue => e
      log "EXTRA_AUTOTILES populate failed: #{e.class}: #{e.message}"
    end
  end

  # Terrain tag / passability / priority data is written directly into
  # Tilesets.rxdata by the XPX editor on save (see retroimport plugin's
  # tileset_export.py), so Essentials loads it natively — no runtime
  # overlay needed.  The JSON-based overlay path that used to live here
  # was removed once the direct-write approach was verified working.
end

XPX.boot

# ── Patch TilemapRenderer for N-layer support ────────────────────────────────
# TilemapRenderer is defined in Scripts.rxdata which loads AFTER this preload
# script runs. We cannot patch it here directly. Instead we hook Game_Map#setup,
# which fires AFTER all scripts are loaded but BEFORE any Spriteset_Map (and thus
# TilemapRenderer) instance is created. This is the earliest reliable patch point.

# ── TilemapRenderer#update wrapping (was prepend, now alias-chain) ────────
#
# Same prepend-vs-alias incompatibility that bit Game_Map: if a plugin
# does `class TilemapRenderer; alias my_old_update update; def update;
# my_old_update; ...; end; end` while we have a prepended module, the
# plugin's alias captures OUR setup and infinite-recurses through super.
#
# Some Essentials plugins DO touch TilemapRenderer for visual effects
# (lighting overlays, weather, custom day/night cycles) and use the
# alias-and-redefine idiom. To avoid the same crash class as Phantom
# hit with Speech Bubble, we wrap update via alias-chain instead of
# prepend.
#
# Resize @tiles to match map.data.zsize lazily in update, BEFORE the
# original update runs. Two directions:
#
#   GROW (current < needed): new layers were added (e.g. transferring INTO
#     a 9-layer XPX map from a 3-layer Essentials map). Append fresh
#     TileSprite instances per cell so the iteration in TilemapRenderer's
#     update has somewhere to write the new layer's tile bitmaps.
#
#   SHRINK (current > needed): we transferred OUT of a multi-layer map
#     into a smaller-layer map (or back to a vanilla 3-layer Essentials
#     map). If we don't shrink @tiles to match, TilemapRenderer's update
#     iterates the stale extra layers, but `$game_map.data[x, y, z]` for
#     z >= zsize returns NIL (mkxp-z's Table.[] doesn't 0-pad OOB reads).
#     Vanilla refresh_tile_bitmap then does `if priority < something` on
#     a nil tile_id and crashes with "undefined method `<' for nil:NilClass".
#     This is exactly the bug Phantombass hit on 2026-05-08 transferring
#     between maps with different layer counts.
#
# Both directions set @need_refresh so any tiles that already had bitmaps
# get re-rendered for the new layer/data layout.
$xpx_tilemap_wrapped = false

def _xpx_install_tilemap_update_wrap(klass)
  return if $xpx_tilemap_wrapped
  $xpx_tilemap_wrapped = true
  begin
    klass.class_eval do
      alias_method :_xpx_orig_tilemap_update, :update
      define_method(:update) do
        if $game_map && $game_map.data
          needed = $game_map.data.zsize rescue 0
          current = (@tiles[0][0].size rescue 0)
          if needed > current && current > 0
            # GROW: append fresh TileSprite instances per cell.
            tile_class = self.class.const_get(:TileSprite)
            @tiles.each do |col|
              col.each do |coord|
                while coord.size < needed
                  coord << tile_class.new(@viewport)
                end
              end
            end
            @need_refresh = true
            xpx_puts "Grew TilemapRenderer tiles: #{current} -> #{needed} layers"
          elsif needed < current && needed > 0 && current > 0
            # SHRINK: pop and dispose excess TileSprites.
            disposed = 0
            @tiles.each do |col|
              col.each do |coord|
                while coord.size > needed
                  sprite = coord.pop
                  if sprite && sprite.respond_to?(:dispose) &&
                     sprite.respond_to?(:disposed?) && !sprite.disposed?
                    begin
                      sprite.dispose
                      disposed += 1
                    rescue
                      # Some TileSprite implementations raise on dispose
                      # if the underlying bitmap is already gone.
                      # Swallow — GC will collect.
                    end
                  end
                end
              end
            end
            @need_refresh = true
            xpx_puts "Shrunk TilemapRenderer tiles: #{current} -> #{needed} layers (disposed #{disposed} sprites)"
          end
        end
        _xpx_orig_tilemap_update
      end
    end
    xpx_puts "TilemapRenderer#update wrapped (alias chain — plugin-friendly)"
  rescue => e
    xpx_puts "TilemapRenderer wrap error: #{e.message}"
    $xpx_tilemap_wrapped = false  # allow retry
  end
end


# ── Scene_Map#update wrapping (variant swap polling) ───────────────────────
# Wraps Scene_Map#update via alias-chain (same plugin-friendly pattern as
# the Game_Map setup wrap and the TilemapRenderer wrap above) so the
# variant-swap check runs once per frame.
#
# The check is gated FIVE ways inside XPX.check_variant_swap (autorun
# running, message open, move-route forcing, already transferring,
# scene type) so the per-frame cost in the common case is just a
# handful of state reads — cheap enough to run every frame without a
# noticeable hit even on Pi-class hardware.
$xpx_scene_map_wrapped = false

def _xpx_install_scene_map_update_wrap(klass)
  return if $xpx_scene_map_wrapped
  $xpx_scene_map_wrapped = true
  begin
    klass.class_eval do
      alias_method :_xpx_orig_scene_map_update, :update
      define_method(:update) do
        _xpx_orig_scene_map_update
        # Variant flip check happens AFTER the vanilla update so the
        # current frame finishes its event interpreter pass first
        # (catches the case where an event command flips the trigger
        # switch on this very frame; we let the rest of the
        # autorun finish, then react on the next clean frame).
        XPX.check_variant_swap rescue nil
      end
    end
    xpx_puts "Scene_Map#update wrapped (variant swap polling)"
  rescue => e
    xpx_puts "Scene_Map update wrap error: #{e.message}"
    $xpx_scene_map_wrapped = false   # allow retry on next definition
  end
end


# ── Patch AutotileBitmaps#add for is_water_type override ────────────────────
# When an autotile has an is_water_type entry in $xpx_autotile_db, this
# patch overrides what AutotileBitmaps#add would normally produce so the
# user's explicit choice — water-type or ground-type — wins over the
# runtime's pixel-content heuristic.
#
# Branches:
#   true   → overwrite all 48 pattern slots with pattern 46 (full
#            interior). Water surfaces render seamlessly regardless of
#            neighbour config.
#   false  → reconstruct each pattern slot from orig_bitmap using the
#            canonical 47-pattern atlas. Bypasses the runtime's water
#            heuristic for autotiles whose pixel content (e.g. dark
#            top-edge strip) would otherwise trigger water classification
#            even though the user said "treat as ground". Without this,
#            the runtime renders corner tiles as flat squares of the
#            source texture instead of the bordered ground pattern.
#   nil    → standard expansion (runtime applies its own heuristic).
#
# Defensive: missing $xpx_autotile_db, malformed entries, or nil
# is_water_type all degrade to standard expansion. Worst case is
# stock v21 behavior, so the patch never makes things worse than
# pre-patch.
#
# TracePoint :end fires when AutotileBitmaps' class body finishes
# evaluating. AutotileBitmaps is nested under TilemapRenderer (defined
# in 001_TilemapRenderer.rb), so we trace for the class name match.

# Canonical 47-entry atlas serialised from autotile.py:AUTOTILE_SUBTILE_RECTS.
# Each entry: [tl_x, tl_y, tr_x, tr_y, bl_x, bl_y, br_x, br_y] — pixel
# coordinates of the four 16×16 sub-tiles within the 96×128 frame-0 source.
# Pattern indexes 0..46; the runtime's TILES_PER_AUTOTILE is 48 so we wrap
# index 47 to 46 (interior) inside the patch.
XPX_AUTOTILE_PATTERN_RECTS = [
  [0, 0, 16, 0, 0, 16, 16, 16],  # pat 0
  [16, 32, 16, 0, 16, 112, 16, 16],  # pat 1
  [0, 48, 80, 48, 0, 16, 16, 16],  # pat 2
  [64, 0, 80, 48, 16, 112, 16, 16],  # pat 3
  [32, 64, 80, 48, 16, 112, 16, 16],  # pat 4
  [0, 0, 64, 32, 0, 16, 64, 112],  # pat 5
  [16, 32, 64, 32, 16, 112, 64, 112],  # pat 6
  [0, 48, 80, 0, 0, 16, 64, 112],  # pat 7
  [64, 0, 80, 0, 16, 112, 64, 112],  # pat 8
  [32, 64, 80, 0, 16, 112, 64, 112],  # pat 9
  [0, 48, 48, 64, 0, 16, 64, 112],  # pat 10
  [64, 0, 48, 64, 16, 112, 64, 112],  # pat 11
  [32, 64, 48, 64, 16, 112, 64, 112],  # pat 12
  [0, 0, 16, 0, 0, 96, 80, 96],  # pat 13
  [16, 32, 16, 0, 64, 16, 80, 96],  # pat 14
  [0, 48, 80, 48, 0, 96, 80, 96],  # pat 15
  [64, 0, 80, 48, 64, 16, 80, 96],  # pat 16
  [32, 64, 80, 48, 64, 16, 80, 96],  # pat 17
  [0, 0, 64, 32, 0, 96, 80, 16],  # pat 18
  [16, 32, 64, 32, 64, 16, 80, 16],  # pat 19
  [0, 48, 80, 0, 0, 96, 80, 16],  # pat 20
  [64, 0, 80, 0, 64, 16, 80, 16],  # pat 21
  [32, 64, 80, 0, 64, 16, 80, 16],  # pat 22
  [0, 48, 48, 64, 0, 96, 80, 16],  # pat 23
  [64, 0, 48, 64, 64, 16, 80, 16],  # pat 24
  [32, 64, 48, 64, 64, 16, 80, 16],  # pat 25
  [0, 0, 64, 32, 0, 96, 48, 80],  # pat 26
  [16, 32, 64, 32, 64, 16, 48, 80],  # pat 27
  [0, 48, 80, 0, 0, 96, 48, 80],  # pat 28
  [64, 0, 80, 0, 64, 16, 48, 80],  # pat 29
  [32, 64, 80, 0, 64, 16, 48, 80],  # pat 30
  [0, 48, 48, 64, 0, 96, 48, 80],  # pat 31
  [64, 0, 48, 64, 64, 16, 48, 80],  # pat 32
  [32, 64, 48, 64, 64, 16, 48, 80],  # pat 33
  [16, 32, 16, 0, 32, 80, 80, 96],  # pat 34
  [64, 0, 80, 48, 32, 80, 80, 96],  # pat 35
  [32, 64, 80, 48, 32, 80, 80, 96],  # pat 36
  [16, 32, 64, 32, 32, 80, 80, 16],  # pat 37
  [64, 0, 80, 0, 32, 80, 80, 16],  # pat 38
  [32, 64, 80, 0, 32, 80, 80, 16],  # pat 39
  [64, 0, 48, 64, 32, 80, 80, 16],  # pat 40
  [32, 64, 48, 64, 32, 80, 80, 16],  # pat 41
  [16, 32, 64, 32, 32, 80, 48, 80],  # pat 42
  [64, 0, 80, 0, 32, 80, 48, 80],  # pat 43
  [32, 64, 80, 0, 32, 80, 48, 80],  # pat 44
  [64, 0, 48, 64, 32, 80, 48, 80],  # pat 45
  [32, 64, 48, 64, 32, 80, 48, 80],  # pat 46
].freeze

module XPX_AutotileWaterPatch
  HALF = 16  # sub-tile size in pixels

  def add(filename)
    return if (defined?(nil_or_empty?) && nil_or_empty?(filename)) ||
              filename.nil? || filename.empty?
    # Already loaded? Increment refcount via super (calls original).
    if @bitmaps && @bitmaps[filename]
      return super
    end

    # Database lookup with defensive fallback.
    db = (defined?($xpx_autotile_db) && $xpx_autotile_db.is_a?(Hash)) ? $xpx_autotile_db : nil
    entry = db ? db[filename] : nil
    water_override = entry.is_a?(Hash) ? entry['is_water_type'] : nil

    # nil → no override, runtime heuristic decides.
    # false → defer to v21's stock AutotileExpander.expand. The earlier
    #         "force-ground" custom expansion used XPX's pattern atlas
    #         (XPX_AUTOTILE_PATTERN_RECTS, 47 entries with XPX's own
    #         numbering) which doesn't match v21's AUTOTILE_PATTERNS
    #         (48 entries with v21's numbering). build_map encodes
    #         tile_ids with v21 patterns from NEIGHBORS_TO_AUTOTILE_INDEX,
    #         so the renderer reads slot N expecting v21 pattern N —
    #         and the patch was writing XPX pattern N there instead,
    #         causing the wrong corner/edge tiles to render. v21's
    #         stock expander does the right thing, so just step aside.
    # true  → still custom-handled below. Forcing water surfaces flat
    #         (every pattern slot = pattern 46 interior) is a real
    #         override that v21 doesn't do natively.
    return super if water_override.nil? || water_override == false

    orig_bitmap = pbGetAutotile(filename)
    @bitmap_wraps[filename] = false
    duration = TilemapRenderer::AUTOTILE_FRAME_DURATION
    duration = $~[1].to_i if filename[/\[\s*(\d+?)\s*\]\s*$/]
    @frame_durations[filename] = duration.to_f / 20

    bitmap = TilemapRenderer::AutotileExpander.expand(orig_bitmap)

    # Layout depends on which expansion shape AutotileExpander produced:
    #   1. height == SOURCE_TILE_HEIGHT      → static, no patterns to override
    #   2. height < TILES_PER_AUTOTILE * 32  → wrapped (two-column layout)
    #   3. height >= TILES_PER_AUTOTILE * 32 → full vertical strip
    src_h = TilemapRenderer::SOURCE_TILE_HEIGHT
    src_w = TilemapRenderer::SOURCE_TILE_WIDTH
    tpa   = TilemapRenderer::TILES_PER_AUTOTILE

    if water_override == true
      # ── Water-type true: every pattern slot becomes the interior ──────
      # CRITICAL pattern-numbering note: XPX's editor atlas uses
      # pattern 46 = interior. v21's AUTOTILE_PATTERNS uses pattern 0 =
      # interior (NEIGHBORS_TO_AUTOTILE_INDEX[255] = 0 confirms it —
      # "fully surrounded → pattern 0"). The expanded bitmap produced
      # by AutotileExpander.expand uses v21's numbering, so the
      # interior row sits at y = 0, NOT y = 46*src_h. Earlier code
      # used 46*src_h and copied the ISOLATED row to every slot, which
      # made water=true autotiles render as 4 outer corners forever
      # — exactly the opposite of "seamless flat water".
      if bitmap.height >= src_h * tpa
        # Full vertical strip — pattern 0 (interior) at y=0.
        interior_y = 0
        override = Bitmap.new(bitmap.width, bitmap.height)
        tpa.times do |pat|
          src_rect = Rect.new(0, interior_y, bitmap.width, src_h)
          override.blt(0, pat * src_h, bitmap, src_rect)
        end
        bitmap.dispose
        bitmap = override

      elsif bitmap.height > src_h
        # Wrapped two-column. Pattern 0 lives in the LEFT column at
        # y=0; v21's wrap places pat 0..tpa/2-1 left, tpa/2..tpa-1
        # right, so we read from x=frame_x (left col), y=0.
        frames = [bitmap.width / (src_w * 2), 1].max
        interior_y = 0
        override = Bitmap.new(bitmap.width, bitmap.height)
        frames.times do |fi|
          frame_x = fi * src_w * 2
          src_rect = Rect.new(frame_x, interior_y, src_w, src_h)
          (tpa / 2).times do |pat_low|
            override.blt(frame_x, pat_low * src_h, bitmap, src_rect)
          end
          (tpa / 2).times do |pat_high|
            override.blt(frame_x + src_w, pat_high * src_h, bitmap, src_rect)
          end
        end
        bitmap.dispose
        bitmap = override
        @bitmap_wraps[filename] = true

      else
        # Static — no patterns to override.
      end

    else
      # ── Force-ground (water_override == false) ─────────────────────────
      # Reconstruct every pattern slot from orig_bitmap using the canonical
      # atlas, bypassing whatever the runtime's stock expander chose. This
      # is the inverse of the water case: instead of all-46, we write each
      # pattern's correct 4 sub-tiles into the corresponding slot.
      if bitmap.height >= src_h * tpa
        # Full vertical strip. Expanded layout for non-wrap is
        #   width  = frames * src_w   (each anim frame occupies one 32-px col)
        #   height = tpa * src_h      (48 patterns stacked vertically)
        # Source orig_bitmap is laid out as N successive 96×128 frames
        # (frame fi at orig x = fi * 96), where the canonical atlas
        # rects address frame-0 pixel coords.
        #
        # Earlier versions of this patch only filled frame 0 of override
        # and left frames 1..N-1 transparent, which made every animated
        # ground-type autotile blink to invisible 7/8 of the time
        # (renderer cycles through frames). Now we iterate frames.
        frames = [bitmap.width / src_w, 1].max
        override = Bitmap.new(bitmap.width, bitmap.height)
        frames.times do |fi|
          frame_dest_x = fi * src_w
          frame_orig_x = fi * (src_w * 3)  # 96-wide source frames
          tpa.times do |pat|
            rects = XPX_AUTOTILE_PATTERN_RECTS[pat % XPX_AUTOTILE_PATTERN_RECTS.length] ||
                    XPX_AUTOTILE_PATTERN_RECTS[0]
            dy = pat * src_h
            override.blt(frame_dest_x,        dy,        orig_bitmap,
                         Rect.new(frame_orig_x + rects[0], rects[1], HALF, HALF))
            override.blt(frame_dest_x + HALF, dy,        orig_bitmap,
                         Rect.new(frame_orig_x + rects[2], rects[3], HALF, HALF))
            override.blt(frame_dest_x,        dy + HALF, orig_bitmap,
                         Rect.new(frame_orig_x + rects[4], rects[5], HALF, HALF))
            override.blt(frame_dest_x + HALF, dy + HALF, orig_bitmap,
                         Rect.new(frame_orig_x + rects[6], rects[7], HALF, HALF))
          end
        end
        bitmap.dispose
        bitmap = override

      elsif bitmap.height > src_h
        # Wrapped two-column — animated source. Each frame is src_w wide
        # in orig_bitmap and src_w*2 wide in the expanded bitmap. Patterns
        # 0..tpa/2-1 go in the left column, tpa/2..tpa-1 in the right.
        frames = [bitmap.width / (src_w * 2), 1].max
        override = Bitmap.new(bitmap.width, bitmap.height)
        frames.times do |fi|
          frame_orig_x = fi * src_w
          frame_dest_x = fi * src_w * 2
          (tpa / 2).times do |pat_low|
            pat = pat_low
            rects = XPX_AUTOTILE_PATTERN_RECTS[pat % XPX_AUTOTILE_PATTERN_RECTS.length] ||
                    XPX_AUTOTILE_PATTERN_RECTS[0]
            dy = pat_low * src_h
            override.blt(frame_dest_x,        dy,        orig_bitmap, Rect.new(frame_orig_x + rects[0], rects[1], HALF, HALF))
            override.blt(frame_dest_x + HALF, dy,        orig_bitmap, Rect.new(frame_orig_x + rects[2], rects[3], HALF, HALF))
            override.blt(frame_dest_x,        dy + HALF, orig_bitmap, Rect.new(frame_orig_x + rects[4], rects[5], HALF, HALF))
            override.blt(frame_dest_x + HALF, dy + HALF, orig_bitmap, Rect.new(frame_orig_x + rects[6], rects[7], HALF, HALF))
          end
          (tpa / 2).times do |pat_high|
            pat = (tpa / 2) + pat_high
            rects = XPX_AUTOTILE_PATTERN_RECTS[pat % XPX_AUTOTILE_PATTERN_RECTS.length] ||
                    XPX_AUTOTILE_PATTERN_RECTS[0]
            dy = pat_high * src_h
            override.blt(frame_dest_x + src_w,        dy,        orig_bitmap, Rect.new(frame_orig_x + rects[0], rects[1], HALF, HALF))
            override.blt(frame_dest_x + src_w + HALF, dy,        orig_bitmap, Rect.new(frame_orig_x + rects[2], rects[3], HALF, HALF))
            override.blt(frame_dest_x + src_w,        dy + HALF, orig_bitmap, Rect.new(frame_orig_x + rects[4], rects[5], HALF, HALF))
            override.blt(frame_dest_x + src_w + HALF, dy + HALF, orig_bitmap, Rect.new(frame_orig_x + rects[6], rects[7], HALF, HALF))
          end
        end
        bitmap.dispose
        bitmap = override
        @bitmap_wraps[filename] = true

      else
        # Static — no patterns to override. Pass through unchanged.
      end
    end

    self[filename] = bitmap
    if bitmap.height > src_h && bitmap.height < tpa * src_h
      @bitmap_wraps[filename] = true
    end
    orig_bitmap.dispose if orig_bitmap && orig_bitmap != bitmap
    @load_counts[filename] = 1
  rescue => e
    XPX.log "AutotileBitmaps#add patch error for #{filename}: " \
            "#{e.class}: #{e.message} — falling back to super"
    super
  end
end

begin
  _xpx_at_tp = TracePoint.new(:end) do |tp|
    if tp.self.is_a?(Class) && tp.self.name == "TilemapRenderer::AutotileBitmaps"
      _xpx_at_tp.disable
      unless tp.self.ancestors.include?(XPX_AutotileWaterPatch)
        tp.self.prepend(XPX_AutotileWaterPatch)
        XPX.log "AutotileBitmaps patched for is_water_type override (true/false)"
      end
      # By the time AutotileBitmaps' class body finishes evaluating,
      # EXTRA_AUTOTILES has already been assigned at the top of the
      # same file (001_TilemapRenderer.rb defines it on line 40 in v21,
      # AutotileBitmaps starts at line 122). Populate it now from
      # XPX_Tilesets.json.
      XPX.populate_extra_autotiles
    end
  end
  _xpx_at_tp.enable
rescue => e
  xpx_puts "AutotileBitmaps TracePoint setup error: #{e.message}"
end


# ── Patch TilesetBitmaps#set_src_rect for XPX-style extras shift ────────────
# v21's design assumes the tileset image has phantom rows for each
# large extra autotile (6 rows × 8 cols = 48 ids per large, +1 id per
# single). When EXTRA_AUTOTILES[tid] has entries, v21 shifts the
# tileset region's tile_ids up but its set_src_rect still uses
# (tile_id - TILESET_START_ID) directly — relying on the user having
# pre-padded their tileset image. XPX projects don't do that, so the
# top-left of the tileset image (= the user's "first tile", usually
# plain grass) ends up at tile_id 480 (with 2 large extras) which
# v21 reads at y = 384 of the image instead of y = 0.
#
# We patch set_src_rect to subtract the per-tileset extras shift
# stored by Game_Map#setup, so the tileset image stays unmodified
# and tile_id 480 maps to (0, 0) like the user expects.
module XPX_TilesetExtrasShiftPatch
  def set_src_rect(tile, tile_id)
    return if (defined?(nil_or_empty?) && nil_or_empty?(tile.filename)) ||
              tile.filename.nil? || tile.filename.empty?
    return if !@bitmaps[tile.filename]
    shift = (defined?($xpx_tileset_extras_shift) &&
             $xpx_tileset_extras_shift.is_a?(Hash)) ?
            ($xpx_tileset_extras_shift[tile.filename] || 0) : 0
    if shift > 0
      adjusted = tile_id - shift
      tpr = TilemapRenderer::TILESET_TILES_PER_ROW
      sw  = TilemapRenderer::SOURCE_TILE_WIDTH
      sh  = TilemapRenderer::SOURCE_TILE_HEIGHT
      tss = TilemapRenderer::TILESET_START_ID
      tile.src_rect.x = ((adjusted - tss) % tpr) * sw
      tile.src_rect.y = ((adjusted - tss) / tpr) * sh
      if @bitmap_wraps[tile.filename]
        height = @bitmaps[tile.filename].height
        col = (adjusted - tss) * sh / (tpr * height)
        tile.src_rect.x += col * tpr * sw
        tile.src_rect.y -= col * height
      end
    else
      super
    end
  rescue => e
    XPX.log "TilesetBitmaps#set_src_rect patch error for " \
            "#{tile.filename}: #{e.class}: #{e.message} — falling back"
    super
  end
end

begin
  _xpx_ts_tp = TracePoint.new(:end) do |tp|
    if tp.self.is_a?(Class) && tp.self.name == "TilemapRenderer::TilesetBitmaps"
      _xpx_ts_tp.disable
      unless tp.self.ancestors.include?(XPX_TilesetExtrasShiftPatch)
        tp.self.prepend(XPX_TilesetExtrasShiftPatch)
        XPX.log "TilesetBitmaps patched for XPX extras-shift remap"
      end
    end
  end
  _xpx_ts_tp.enable
rescue => e
  xpx_puts "TilesetBitmaps TracePoint setup error: #{e.message}"
end


# ── EXTRA_AUTOTILES populate fallback ───────────────────────────────────────
# If the AutotileBitmaps TracePoint above doesn't fire for any reason
# (e.g. a fork that splits TilemapRenderer across multiple files),
# Game_Map#setup is a reliable fallback: it runs once per map load,
# after all scripts have evaluated. We guard with a one-shot flag so
# the populate runs at most once even across map transitions.

# ── Game_Map#setup wrapping — alias-and-redefine, NOT prepend ─────────────
#
# We need to populate EXTRA_AUTOTILES the first time Game_Map#setup is
# called for a map, as a fallback for cases where the AutotileBitmaps
# TracePoint patch didn't fire. The obvious approach is `prepend` a
# module with a setup that does the populate then `super`s — but this
# is FUNDAMENTALLY INCOMPATIBLE with how Essentials plugins extend
# Game_Map.
#
# Why prepend breaks: most Essentials plugins (incl. Carmaniac's
# Speech Bubble, Modular Messages, EBDX, etc.) use the
# alias-and-redefine idiom:
#
#     class Game_Map
#       alias my_old_setup setup
#       def setup(map_id)
#         my_old_setup(map_id)
#         do_plugin_thing
#       end
#     end
#
# When Ruby's `alias` keyword resolves `:setup`, it walks the method
# dispatch chain — INCLUDING prepended modules. So `my_old_setup` ends
# up bound to OUR prepended setup. At runtime:
#
#   instance.setup → MRO: [Our prepended setup, Game_Map#setup]
#     → Our setup runs → super
#       → Game_Map#setup is now plugin's redefined version
#         → plugin calls my_old_setup (our setup again)
#           → super → Game_Map#setup (plugin's again)
#             → my_old_setup → our setup → ∞
#
# Phantombass hit exactly this with Speech Bubble: stack-overflow
# crash with the trace pinging between speech bubble line 555 and
# XPX_Preload's setup wrapper.
#
# alias-and-redefine OURSELVES composes correctly with other plugins'
# alias-and-redefines because each layer captures whatever the current
# Game_Map#setup is at that moment, and calls it linearly. No MRO
# reentry, no infinite loop. We use Module#method_added to detect
# when setup is first defined on Game_Map (after Scripts.rxdata
# loads), wrap it once, and then any further plugin alias-and-redefines
# automatically chain through us correctly.
#
# Trade-off vs prepend: if a plugin redefines setup WITHOUT aliasing
# (just `def setup; ...; end` with no chaining), our wrapper is bypassed
# and EXTRA_AUTOTILES doesn't populate via this fallback — but the
# AutotileBitmaps TracePoint path usually catches it anyway. That kind
# of plugin would also be silently breaking Essentials' own setup, so
# they're already in undefined-behavior territory.

# Bridge fix #3 state. The actual hook installation is consolidated
# with the audio-Hash patch's method_added below — see "Consolidated
# Module#method_added hook" further down in this file. Both checks
# live in one method_added override to avoid stacking two hooks
# (which doubles the per-`def` overhead on every plugin load).
$xpx_setup_wrapped = false

# Helper called from the consolidated method_added hook when
# Game_Map#setup is first defined. Wraps it via alias chain so XPX's
# extras-populate + cache-eviction work runs before the original
# setup, while still composing correctly with plugins that use the
# alias-and-redefine idiom (Speech Bubble, EBDX, etc.).
def _xpx_install_game_map_setup_wrap(klass)
  return if $xpx_setup_wrapped
  $xpx_setup_wrapped = true
  begin
    klass.class_eval do
      alias_method :_xpx_orig_setup, :setup
      define_method(:setup) do |map_id|
        unless $xpx_extras_populated
          $xpx_extras_populated = true
          XPX.populate_extra_autotiles rescue nil
        end
        # ── Cache eviction (bridge fix #1) ───────────────────────────
        # $xpx_map_cache and $data_maps both cache the same RPG::Map
        # instance per map id. Plugins that mutate the data layer
        # (event.condition.switch1_id = X, etc.) saw mutations
        # PERSIST across transfers, since the same instance was
        # re-served. Evict on each setup so the next load_data call
        # rebuilds fresh — plugins that assume "fresh state on map
        # entry" now get what they expect.
        #
        # $xpx_map_dict_cache (the parsed-JSON layer) is NOT evicted:
        # the underlying file is stable within a session, plugin
        # mutations happen on the BUILT RPG::Map (which IS evicted),
        # and re-parsing multi-MB JSON on every setup was causing the
        # Essentials debug-menu warp to trigger RGSS's "unresponsive
        # script" watchdog. See the get_map two-layer comment above.
        # Net effect: fresh RPG::Map instance per setup (correctness),
        # but build_map runs on a cached dict (fast).
        if $xpx_map_cache && $xpx_map_cache.is_a?(Hash)
          $xpx_map_cache.delete(map_id)
        end
        if $data_maps && $data_maps.is_a?(Hash)
          $data_maps.delete(map_id)
        end
        _xpx_orig_setup(map_id)
        # ── Per-map EXTRA_AUTOTILES injection ────────────────────────
        # XPX assigns autotiles per-MAP, not per-tileset. v21's
        # EXTRA_AUTOTILES is keyed by tileset_id, so we mirror the
        # current map's autotile data into EXTRA_AUTOTILES[tid] right
        # before Spriteset_Map.new runs add_extra_autotiles. Two maps
        # sharing a tileset can have completely different autotile
        # sets — flipping EXTRA_AUTOTILES[tid] each setup is what
        # makes that work.
        #
        # build_map populated $xpx_map_extras[map_id] from the map's
        # `autotile_paths`. Now we copy the large/single arrays into
        # the v21 hash. If EXTRA_AUTOTILES isn't defined yet (which
        # happens on first boot if Essentials's TilemapRenderer
        # hasn't loaded), skip silently — Essentials will load
        # eventually and on the next setup we'll have access.
        begin
          map_extras = ($xpx_map_extras || {})[map_id]
          if map_extras
            # Game_Map exposes the underlying RPG::Map via @map after
            # _xpx_orig_setup runs. We use that for tileset_id rather
            # than $game_map.tileset_id because Game_Map has no public
            # tileset_id accessor in stock v21 — `$game_map.tileset_id`
            # only works when a plugin/hotfix defines one (it would
            # silently rescue to 1 otherwise, masking real lookups).
            tid = (@map.tileset_id rescue 1)
            # ── Legacy slots 0-6 ─────────────────────────────────────
            # CRITICAL ordering note: _xpx_orig_setup → updateTileset
            # COPIES tileset.autotile_names into Game_Map's own
            # @autotile_names instance var. The renderer reads
            # `map.autotile_names` from Game_Map (not the tileset).
            # So flipping $data_tilesets[tid].autotile_names AFTER
            # setup runs has no effect on the renderer — we must write
            # `self.autotile_names` directly on this Game_Map instance.
            # We ALSO update the tileset for any plugin code that
            # reads $data_tilesets[tid].autotile_names directly.
            legacy = Array(map_extras["legacy"] || [])
            if !legacy.empty?
              padded = (0..6).map {|i| (legacy[i] || "").to_s }
              self.autotile_names = padded rescue nil
              if $data_tilesets && $data_tilesets[tid]
                $data_tilesets[tid].autotile_names = padded rescue nil
              end
              # Diagnostic: read back to confirm the write stuck.
              # Some plugins redefine autotile_names= as a tileset
              # passthrough — if that's happening, what we read back
              # won't match `padded`.
              if XPX_DEV_MODE
                actual = self.autotile_names rescue nil
                XPX.log "Setup map=#{map_id} tid=#{tid}: " \
                        "legacy=#{padded.inspect} actual=#{actual.inspect}"
              end
            end
            # ── Slots 7+: inject into v21's EXTRA_AUTOTILES hash ─────
            # Renderer reads EXTRA_AUTOTILES[tid] directly (not via
            # Game_Map), so flipping it here works. Done AFTER setup
            # so we can read self.tileset_id reliably.
            #
            # IMPORTANT: in v21, EXTRA_AUTOTILES is a class constant on
            # TilemapRenderer, NOT a top-level constant. Object.const_get
            # raises NameError. Use the resolver helper which checks the
            # canonical class scope first.
            ea = XPX.resolve_extra_autotiles
            if ea.is_a?(Hash)
              large_arr  = Array(map_extras["large"]  || [])
              single_arr = Array(map_extras["single"] || [])
              ea[tid] = [large_arr, single_arr]
              # Track per-tileset extras shift so our patched
              # TilesetBitmaps.set_src_rect can subtract it. v21's
              # design assumes the tileset image has phantom rows for
              # each large extra autotile (6 rows × 8 cols = 48 ids
              # per large, +1 id per single). XPX projects don't pad
              # their tileset images that way, so we have to remap
              # the tile_id at src_rect compute time instead.
              shift = (large_arr.length * 48) + single_arr.length
              ts_name = ($data_tilesets && $data_tilesets[tid]) ?
                        $data_tilesets[tid].tileset_name.to_s : ""
              $xpx_tileset_extras_shift ||= {}
              $xpx_tileset_extras_shift[ts_name] = shift unless ts_name.empty?
              if XPX_DEV_MODE
                XPX.log "Setup map=#{map_id} tid=#{tid}: " \
                        "EXTRA_AUTOTILES[#{tid}]=#{ea[tid].inspect} " \
                        "tileset='#{ts_name}' shift=#{shift}"
              end
            end
          end
        rescue => e
          xpx_puts "Per-map autotile inject failed: #{e.message}"
        end
      end
    end
    xpx_puts "Game_Map#setup wrapped (alias chain + cache eviction)"
  rescue => e
    xpx_puts "Game_Map setup wrap error: #{e.message}"
    $xpx_setup_wrapped = false  # allow retry on next setup definition
  end
end


# ── Method_added hook to patch TilemapRenderer ──────────────────────────────
# TracePoint(:end) doesn't fire in mkxp-z's script eval context.
# Game_Map#setup in preload gets overwritten by Scripts.rxdata.
# Method_added fires for EVERY method definition — we intercept TilemapRenderer#initialize
# and prepend our patch the instant it's defined, before any instance is created.

# Hook Game startup to log each step
module Game
  class << self
    alias :_xpx_orig_initialize :initialize rescue nil
    def initialize
      XPX.log "Game.initialize: loading Animations.rxdata..." rescue nil
      _xpx_orig_initialize
      XPX.log "Game.initialize: complete. start_map_id=#{$data_system&.start_map_id}" rescue nil
    rescue => e
      XPX.log "Game.initialize ERROR: #{e.message}
#{e.backtrace.first(5).join('
')}" rescue nil
      raise
    end
  end
end rescue nil

# (TilemapRenderer logging hook removed — TracePoint patch above handles init logging)

# ── Patch audio system to handle Hash audio args at all call sites ───────────
# Essentials v21 move_type_custom stores door sounds as plain Ruby Hashes.
# pbSEPlay calls .name on the argument and crashes if it receives a Hash.
# We patch at two levels:
# 1. RPG::AudioFile.new accepts a Hash — fixes construction-time issues
# 2. Wrap pbSEPlay/pbBGMPlay etc via method_added so the wrap applies
#    the moment each method is defined, regardless of load order.

# Level 1: RPG::AudioFile.new accepts Hash
begin
  class RPG::AudioFile
    class << self
      alias :_xpx_orig_new :new rescue nil
      def new(name_or_hash = "", volume = 100, pitch = 100)
        if name_or_hash.is_a?(Hash)
          h = name_or_hash
          _xpx_orig_new(
            (h["name"]  || h[:name]  || "").to_s,
            (h["volume"]|| h[:volume]|| 100).to_i,
            (h["pitch"] || h[:pitch] || 100).to_i
          )
        else
          _xpx_orig_new((name_or_hash || "").to_s, volume.to_i, pitch.to_i)
        end
      end
    end
  end
rescue => e
  xpx_puts "RPG::AudioFile.new patch failed: #{e.message}"
end

# Level 2: patch each audio method the instant it gets defined.
# Use Module.method_added (fires for ALL modules/classes) not Kernel.method_added.
# In Essentials v21, pbSEPlay is a module_function — not defined on Kernel.
# Audio log lives under <GAME_ROOT>/logs/ alongside xpx_debug.log; the
# parent directory was already created by XPX module init at boot.
$xpx_audio_log     = File.join(XPX::LOGS_DIR, "xpx_audio_debug.log")
$xpx_audio_targets = [:pbSEPlay, :pbBGMPlay, :pbBGSPlay, :pbMEPlay, :pbSEFade]
$xpx_audio_patched = {}

# One-shot migration: if an older audio log sits at the project root,
# move it into the logs folder so the user keeps their session history.
begin
  legacy_audio = File.join(XPX::GAME_ROOT, "xpx_audio_debug.log")
  if File.exist?(legacy_audio) && !File.exist?($xpx_audio_log)
    File.rename(legacy_audio, $xpx_audio_log) rescue nil
  end
rescue; end

begin
  File.open($xpx_audio_log, "w") {|f| f.puts "=== XPX Audio Debug #{Time.now} ==="; f.flush}
rescue; end

# ── Consolidated Module#method_added hook (bridge fix #4) ────────────────
# Single override handles BOTH the audio-Hash patch AND the Game_Map#setup
# wrap (bridge fix #3). Previously each lived in its own `class Module`
# block and aliased the previous method_added — so every `def` in every
# Ruby class/module walked through TWO hooks, doubling the overhead at
# script-load time. Consolidating into one method_added cuts that
# overhead in half AND removes a layer of alias chain that was making
# the load order between the two hooks subtle to reason about.
#
# ONE-SHOT INSTALL GUARD (bridge fix #4b — Phantom's SystemStackError):
# Wrap the install in `unless private_method_defined?(:_xpx_orig_method_added)`
# so re-evaluating this `class Module ... end` block (for any reason —
# duplicated preloadScripts entry, mkxp-z re-eval after a script
# reload, an older cached copy of this file getting loaded too) is a
# silent no-op instead of re-aliasing our own wrapper as the "original".
#
# Without the guard, on the second evaluation:
#   1. `alias :_xpx_orig_method_added :method_added` re-points the alias
#      at the current method_added (which IS our wrapper from run 1).
#   2. `def method_added(meth)` redefines the wrapper.
#   3. The wrapper now calls _xpx_orig_method_added → itself → infinite
#      recursion → SystemStackError at the alias-call line the next
#      time any Ruby class defines a method (which is immediately,
#      because Essentials' Scripts.rxdata defines thousands).
#
# `private_method_defined?(:name, true)` checks for the method including
# inherited and private definitions — method_added is private — so this
# returns true after the first install and false before. Effectively a
# Ruby idempotent monkey-patch pattern.
class Module
  unless private_method_defined?(:_xpx_orig_method_added, true)
    alias :_xpx_orig_method_added :method_added rescue nil
    def method_added(meth)
      _xpx_orig_method_added(meth) rescue nil

    # ── Game_Map#setup wrap detection (bridge fix #3) ────────────────
    # Wraps the moment Scripts.rxdata defines setup on Game_Map. The
    # $xpx_setup_wrapped flag short-circuits the re-trigger when our
    # wrapper itself defines the new setup body.
    if meth == :setup && !$xpx_setup_wrapped &&
       self.is_a?(Class) && self.name == "Game_Map"
      _xpx_install_game_map_setup_wrap(self)
    end

    # ── TilemapRenderer#update wrap detection ────────────────────────
    # Same alias-chain pattern as Game_Map#setup. Replaces the older
    # prepend-based hook (TracePoint :end on the class) which had two
    # problems: (1) TracePoint(:end) fires unreliably in mkxp-z's
    # eval mode, and (2) prepend recursion-crashed if any plugin used
    # alias-and-redefine on update. This path fixes both.
    if meth == :update && !$xpx_tilemap_wrapped &&
       self.is_a?(Class) && self.name == "TilemapRenderer"
      _xpx_install_tilemap_update_wrap(self)
    end

    # ── Scene_Map#update wrap detection (variant swap polling) ───────
    # Per-frame hook: after Scene_Map's vanilla update runs, call
    # XPX.check_variant_swap. That function is itself short-circuit-y
    # (returns early when an autorun is running, a message is open,
    # mid-transfer, etc.) so the per-frame cost is one method call +
    # a few state reads when nothing's happening. When a variant
    # condition flips, it sets up a same-id transfer using RGSS's
    # transition_processing pipeline so the engine's own fade
    # machinery handles the visuals.
    if meth == :update && !$xpx_scene_map_wrapped &&
       self.is_a?(Class) && self.name == "Scene_Map"
      _xpx_install_scene_map_update_wrap(self)
    end

    # ── Audio-Hash patch detection ───────────────────────────────────
    # Wraps each audio method the moment it lands so any Hash arg gets
    # coerced into a proper RPG::AudioFile before reaching the runtime
    # call. Tracks which methods we've already patched per-name so a
    # later redefinition of (say) pbSEPlay in the same module doesn't
    # re-wrap and double the audio-log noise.
    if $xpx_audio_targets&.include?(meth) && !$xpx_audio_patched[meth]
      $xpx_audio_patched[meth] = true
      mod = self
      begin
        orig = instance_method(meth)
        define_method(meth) do |audio, *args|
          begin
            File.open($xpx_audio_log, "a") do |f|
              kind = audio.class.name rescue "?"
              val  = audio.is_a?(Hash) ? audio.inspect : kind
              f.puts "#{meth} in #{mod}: #{kind}=#{val}"
              f.puts "  " + caller.first(4).join("
  ") if audio.is_a?(Hash)
              f.flush
            end
          rescue; end
          if audio.is_a?(Hash)
            h = audio
            audio = RPG::AudioFile.new(
              (h["name"]  || h[:name]  || "").to_s,
              (h["volume"]|| h[:volume]|| 80).to_i,
              (h["pitch"] || h[:pitch] ||100).to_i
            ) rescue audio
          end
          orig.bind(self).call(audio, *args)
        end
        xpx_puts "Patched #{mod}##{meth} for Hash audio coercion"
      rescue => e
        xpx_puts "Audio patch #{mod}##{meth} failed: #{e.message}"
      end
    end
    end   # close: def method_added
  end     # close: unless private_method_defined?
end rescue nil

# ── XPX page-condition variable operator patch ───────────────────────────
# RMXP's vanilla Game_Event#refresh evaluates page conditions with the
# variable check hard-coded to ">=". XPX's page-condition editor lets
# the user pick from the full operator set (==, >=, <=, >, <, !=) and
# stores the chosen op as @xpx_variable_operator on the
# RPG::Event::Page::Condition. The patch below intercepts page
# selection so non->= operators behave correctly at runtime.
#
# Op encoding (matches the editor): 0===, 1=>=, 2=<=, 3=>, 4=<, 5=!=
#
# Strategy: prepend a module that replaces the variable comparison
# inline in Game_Event#refresh's page-walk. The patch reuses every
# other RMXP refresh side-effect (sprite update, move_route reset,
# Interpreter spawn, etc.) by calling super after deciding the
# active page itself; we mutate the underlying @event.pages so the
# super refresh sees only the page we picked. That avoids
# duplicating ~30 lines of RMXP setup code that Pokémon Essentials
# is allowed to extend. Falls back silently if Game_Event isn't
# defined yet (Essentials' Scripts.rxdata loads after the preload).
module XPX_GameEventPagePatch
  # Maximum allowed recursion depth into refresh on a single event
  # instance before we pull the plug and bail. Set to 2 so that ONE
  # level of legitimate re-entry is allowed (some plugins legitimately
  # call event.refresh from their own refresh body, expecting the
  # standard chain to run). Anything beyond depth 2 is treated as a
  # runaway loop and short-circuited.
  XPX_REFRESH_MAX_DEPTH = 2

  def refresh
    # Re-entrancy guard for the "Event Indicators" class of plugin
    # bug. Those plugins redefine Game_Event#refresh and at some
    # point call event.refresh (on self or via iteration) from
    # within their own body. With our XPX patch prepended, the
    # chain becomes:
    #
    #   instance.refresh → XPX runs → super → EI's body
    #                                  → EI line 404 calls event.refresh
    #                                    → instance.refresh again (top of MRO)
    #                                      → XPX runs → super → EI body
    #                                        → line 404 → ... ∞
    #
    # We tried three earlier guard shapes, each with a problem:
    #   1) `return super` on re-entry — super lands in EI, which
    #      hits line 404 again, re-triggers the same loop.
    #   2) `return` (no super) on re-entry — breaks the loop, but
    #      also skips Game_Event's standard refresh work (page
    #      selection, sprite update), causing a black screen on new
    #      game when EI's refresh expects that work to have run.
    #   3) Pristine alias via TracePoint(:method_added) — the
    #      TracePoint event :method_added isn't actually valid in
    #      MRI Ruby (only :class, :end, :call, :return, etc. are).
    #      Boot logged "unknown event: method_added" and the alias
    #      never got captured, so we fell through to (2)'s bail
    #      behavior → still black screen.
    #
    # Current shape: depth-limiting. We track an integer recursion
    # depth per instance. The OUTER call (depth 1) runs the full
    # pre-filter + super + restore. ONE level of legitimate re-entry
    # (depth 2) calls super only, no pre-filter — that's enough for
    # plugins that re-call event.refresh and expect the chain to
    # execute. At depth 3+ we bail without super to break runaway
    # loops. Naturally terminates: the loop's expansion at depth 2
    # produces a depth-3 call that bails, depth-2 super returns,
    # and the chain unwinds.
    @_xpx_refresh_depth ||= 0
    @_xpx_refresh_depth += 1
    begin
      if @_xpx_refresh_depth > XPX_REFRESH_MAX_DEPTH
        # Runaway recursion — bail without super to break the cycle.
        return
      end
      if @_xpx_refresh_depth > 1
        # Legitimate re-entry. Skip our pre-filter (the outer call
        # already mutated/restored), just walk the chain.
        return super
      end
      # Depth 1 — outer call. Fall through to the pre-filter logic
      # below.
    ensure
      # The outer-fall-through path also needs the depth decremented
      # at the very end. We use a nested begin/ensure below for
      # that, and the OUTER ensure here handles the early-return
      # paths above (depth > 1). Both contribute to a clean
      # decrement on every exit path.
      if @_xpx_refresh_depth > 1
        @_xpx_refresh_depth -= 1
      end
    end
    # Depth-1 (outer) path. The early-return paths above already
    # handled depth >= 2; here we run the actual pre-filter logic
    # plus super, with a final ensure to decrement the depth on
    # exit (whether via normal return or an exception).
    begin
      if defined?(@event) && @event && @event.respond_to?(:pages) && @event.pages
      # Pre-filter: hide pages whose XPX operator condition fails
      # by giving them a dummy condition that always rejects. We
      # restore originals after super runs. This tactic keeps the
      # rest of refresh's logic (page-changed cleanup, sprite/move
      # init, plugin overrides) intact.
      #
      # Two XPX-only conditions handled here:
      #   1. @xpx_variable_operator — non->= comparison ops on the
      #      variable page-condition.
      #   2. @xpx_switch1_state — false means "switch must be OFF",
      #      which RMXP can't express natively. When that's set we
      #      hide the page when the switch IS on (inverted check).
      hidden = []
      @event.pages.each do |page|
        c = page.condition rescue nil
        next unless c
        reject = false
        # ── Variable operator check ──────────────────────────────
        # XPX-only: non->= operators on the variable page-condition.
        # RMXP's stock evaluation is hard-coded to >=; for any other
        # op we evaluate manually here and flag the page for
        # rejection if it fails.
        if c.variable_valid
          op = (c.instance_variable_get(:@xpx_variable_operator) || 1).to_i
          if op != 1   # op 1 (>=) is RMXP's default — stock handles it.
            a = $game_variables[c.variable_id]
            b = c.variable_value
            pass = case op
                   when 0 then a == b
                   when 2 then a <= b
                   when 3 then a >  b
                   when 4 then a <  b
                   when 5 then a != b
                   else a >= b
                   end
            reject = true unless pass
          end
        end
        # ── Switch1 ON/OFF check ─────────────────────────────────
        # XPX-only: lets the user require Switch 1 to be OFF (RMXP
        # only natively supports "must be ON"). When the user wants
        # OFF: if it's currently ON, fail the page; if it's OFF,
        # temporarily flip switch1_valid=false so RMXP's stock check
        # (which wants ON) doesn't reject the page.
        if c.switch1_valid && !reject
          want_state = c.instance_variable_get(:@xpx_switch1_state)
          want_state = true if want_state.nil?  # default = ON
          unless want_state
            sw_on = $game_switches[c.switch1_id]
            if sw_on
              reject = true
            else
              hidden << [page, :sw1_off, c.switch1_valid]
              c.switch1_valid = false
            end
          end
        end
        # ── Switch2 ON/OFF check (RMXP parity) ───────────────────
        # Same logic as Switch 1 but on the second switch slot. RMXP
        # natively supports two switch conditions; XPX adds the
        # OFF-state extension to both via @xpx_switch2_state.
        if c.switch2_valid && !reject
          want_state = c.instance_variable_get(:@xpx_switch2_state)
          want_state = true if want_state.nil?
          unless want_state
            sw_on = $game_switches[c.switch2_id]
            if sw_on
              reject = true
            else
              hidden << [page, :sw2_off, c.switch2_valid]
              c.switch2_valid = false
            end
          end
        end
        # ── Force-reject mechanism ───────────────────────────────
        # When ANY of the XPX-only checks above fail, we need to
        # make RMXP's stock refresh treat the page as inactive.
        # Previously this used "set switch2_valid=true with id=0"
        # — but that BREAKS the moment the user actually sets
        # Switch 2 as a real condition (RMXP parity feature),
        # because we'd clobber their genuine setting.
        #
        # Instead, force-reject via the VARIABLE slot:
        # @variable_id=0 and @variable_value=99999. RMXP's
        # $game_variables[0] returns 0 (the default for any
        # unallocated variable), 0 >= 99999 is false, so the
        # stock evaluation rejects the page. If the user already
        # has a variable condition set, we save its values first
        # and restore them after super.
        if reject
          hidden << [
            page, :reject,
            c.variable_valid, c.variable_id, c.variable_value,
          ]
          c.variable_valid = true
          c.variable_id    = 0
          c.variable_value = 99999
        end
      end
      begin
        super
      ensure
        hidden.each do |entry|
          page = entry[0]
          c = page.condition
          case entry[1]
          when :sw1_off
            c.switch1_valid = entry[2]
          when :sw2_off
            c.switch2_valid = entry[2]
          when :reject
            c.variable_valid = entry[2]
            c.variable_id    = entry[3]
            c.variable_value = entry[4]
          end
        end
      end
    else
      super
    end
    ensure
      # Decrement the depth counter on every exit path (normal
      # return, super-raised exception, anything). At this point
      # depth was 1 (we're in the outer path); decrementing gets
      # it back to 0, so the next external refresh on this event
      # starts fresh.
      @_xpx_refresh_depth -= 1
    end
  end
end

# ── XPX_GameEventPagePatch is INTENTIONALLY NOT PREPENDED ────────────────
#
# The patch's job was to pre-filter page conditions for two XPX-only
# extensions:
#   1. @xpx_variable_operator (non->= operators on the page-level
#      Variable condition).
#   2. @xpx_switch1_state (allow "switch must be OFF" semantics on
#      the page-level Switch condition).
#
# Both are runtime extensions of niche RMXP page-condition fields
# that most events don't use — vanilla RMXP / Pokémon Essentials
# events default to >= and ON, which the standard refresh handles
# without our help.
#
# The patch is disabled here because prepending Game_Event#refresh
# interacts catastrophically with plugins like Event Indicators that
# call event.refresh from within their own refresh body. Three guard
# shapes were tried (return super / return / pristine-alias) — each
# either crashed with stack overflow OR caused the game to black-
# screen on new game. Even a depth-limited guard ends up scheduling
# enough nested refreshes (combined with EI's per-call iteration of
# all events) that the main game loop can't make forward progress.
#
# What still works without the prepend:
#   • The two XPX ivars are preserved through xpxdata save/load.
#   • The editor's UI still shows the operator dropdown / OFF state
#     toggle, so the data is round-trippable.
#   • Re-imports through retroimport preserve the ivars in rxdata.
#
# What's lost:
#   • Runtime evaluation of non->= variable operators on page conds.
#   • Runtime evaluation of "switch must be OFF" page conditions.
# Workarounds for users who need these:
#   • Use a Conditional Branch event command (full operator set).
#   • Use a Script page condition (arbitrary Ruby).
#
# To re-enable later (e.g. once a non-prepend approach is built),
# delete this comment block and uncomment the original block below.
#
# begin
#   if defined?(Game_Event)
#     Game_Event.prepend(XPX_GameEventPagePatch)
#     xpx_puts "Page-condition operator patch installed."
#   else
#     once_loaded = false
#     trace = TracePoint.new(:class) do |tp|
#       next if once_loaded
#       if tp.self.name == "Game_Event"
#         once_loaded = true
#         Game_Event.prepend(XPX_GameEventPagePatch) rescue nil
#         xpx_puts "Page-condition operator patch installed (deferred)."
#         trace.disable
#       end
#     end
#     trace.enable
#   end
xpx_puts "Page-condition operator patch DISABLED (prepend conflict with Event Indicators / similar plugins)."
begin
  # Keep the surrounding begin block balanced even though the body
  # is now just the puts above. Easier to revert later.
rescue => e
  xpx_puts "Page-condition operator patch failed: #{e.message}"
end
